INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (437, 'Gwaerost', 'castle', 50, '', 'A castle in southwestern Anfalas held by House Maldring of Haerlond. Its stone towers overlook the coastal road; the surrounding estate grows grain and raises sheep on the wind-swept Anfalas plain. The castle is a working garrison and manor combined — practical rather than elegant, with a small garrison and the lord''s household sharing its walls.', '00e5f2d229a2edcf3766d67af82c63af', ST_GeomFromText('POINT(2.943926 40.441266)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (438, 'Rond Deren', 'manor', 15, '', 'A lordly manor tucked in the hills of northern Anfalas between Umb Estelwain and Rond Rhandir, in the County of Agarinna. Rond Deren is a stone manor house with attached farmsteads — a quiet, well-maintained estate of a minor Gondorian noble family who tend their lands and keep out of larger politics.', '033f56d8b661b104d5a147e1a75be0b1', ST_GeomFromText('POINT(6.361441 43.005169)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (439, 'Tarmabar', 'keep', 82, '100% Dúnadan', 'Built by the Tarma family in T.A. 2.. A rural power base and summer retreat for the Lords of Tarma.. The Tarmas are second in power only to the King himself, and they have a history of insubordination against the throne.', '03d2ab1b44e07dd4eda050853c7d7a9e', ST_GeomFromText('POINT(-2.10898 52.659012)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (440, 'Barad Garan', 'ruins', 'Barad Garan stands as a ruin — towers toppled, walls breached — a shell of the fortress it once was. No garrison remains; wind moves through the open gateways and birds nest in the cracked stonework.', '04bc5a40947e50f0eaa4e0a86776c9d1', ST_GeomFromText('POINT(-2.068102 53.013253)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (441, 'Sunthra Unsar', 'city', 6000, 'Dunlendings', 'Originally built under the name Mistalonde, the city appeared in records from the mid-Second Age until T.A. 1503, when Gordaig of Saerlann captured and renamed it Sunthra Unsar. The rebuilt city became the seat of power of the Saerlannish (Dynion) clan, and its inhabitants were almost entirely hillmen.', '04e3220ac767492d0a7e4a40af1cf5f7', ST_GeomFromText('POINT(-0.338526 47.295549)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (442, 'Eolburg', 'town', 220, 'Northmen', 'Buhr Ailgra is one of the few permanent colonies of the Eothraim, who follow the migratory movements of their flocks across the plains of Rhovanion. The village is a simple community with houses built of straw and peat, surrounded by a sturdy earthen fence.', '0573bacfdc7be405711b2229aac84155', ST_GeomFromText('POINT(22.190484 50.535117)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (443, 'Oatbarton', 'village', 200, '50% Harfoot, 40% Stoor, 10% Fallohide', 'Settled in T.A. 1625 by a family from Bree.. Agriculture.. The rural Hobbits of Oatbarton have a fair amount of contact with Men.', '05bfff19fd4ef4921a8ab483a9a1606e', ST_GeomFromText('POINT(-1.144238 51.970683)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (444, 'Tir Elena', 'town', 490, 'Gondor', 'A small Gondorian town of Anórien, on the northeastern eaves of Drúadan Forest — capital and seat of House Elenion, the local barons. Stone houses with tiled roofs line the road through the forest''s edge; the Drúadan Forest is just beyond the tree-line to the south. The Woses of the forest are never seen in town but their presence is always felt.', '06a832f049e40fd2956c67aafa4b97b4', ST_GeomFromText('POINT(17.042721 43.969903)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (445, 'Nornhabar', 'dwarven mine', 84, 'Dwarves', 'The dwarven population varied considerably, having reached its peak in the Second Age. It was mainly abandoned before the War of the Last Alliance and, although never completely deserted, was largely dilapidated by T.A. 1643.', '0780dc18f26046f385079adf790b14cb', ST_GeomFromText('POINT(-6.24766 50.463435)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (446, 'Balost', 'fortress', 132, '60% Dunman/Eriadoran, 35% Cardolani, 5% Dúnadan', 'Completed in T.A. 923 by Hir Girithlin.. A base for administration of rural estates; a strategic strong point in Gwathló valley between Tharbad and Saralainn.. Balost is a sturdy castle which withstood many attacks from without.', '095f5496d06b45426748380218dd28bc', ST_GeomFromText('POINT(0.84075 48.028125)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, external_id, geom) VALUES (447, 'Lindabad', 'manor', 20, '', '097732fb0cf5be220774f197e7b5e939', ST_GeomFromText('POINT(3.339786 42.953196)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (448, 'Hwarin', 'village', 100, '', 'A small coastal village in Rast Rhaen, a sheltered garth on the central Andrast coast. Its few stone houses and fishing boats sit in a protected cove; the people are Dunir fisher-folk who live by the sea and avoid the attention of passing ships.', '09ebe7fb2ead8fce2e13bcb494347b54', ST_GeomFromText('POINT(1.579458 39.692717)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (449, 'Frogmorton', 'village', 230, '60% Harfoot, 30% Fallohide, 10% Stoor', 'Frogmorton is a comfortable Hobbit village on the Great East Road in the Eastfarthing, its central position on the road making it a natural stopping point for travellers crossing the Shire. The local farmers bring their produce to market here on regular days; a decent inn serves the road traffic. The surrounding land is well-farmed and peaceful, typical of the Eastfarthing''s prosperous character.', '0a4b4faabc031f6513c920b1a7889659', ST_GeomFromText('POINT(-0.546626 51.552754)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (450, 'Cair Andros', 'fortress', 560, 'Gondor', 'Cair Andros (S. Ship of Long Foam) was an island fortress on the River Anduin, roughly forty miles north of Osgiliath. Shaped like a great ship with a high rocky prow pointing north, it was fortified by Steward Túrin II to protect Anórien from enemy crossings. It served as a vital northern bulwark of Gondor against Mordor throughout the late Third Age.', '0ad87f9426e41d0331a292db56e11def', ST_GeomFromText('POINT(17.804309 44.121168)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (451, 'Beldwin', 'castle', 475, '60% Dunman, 40% Dúnadan', 'Beldwin is a Dúnadan castle and its surrounding settlement in the northern Westmarch, just south of the River Isen near an ancient stone bridge. It serves as the administrative base for this corner of the region and maintains a garrison that keeps order among the mixed Dunman and Dúnadan population. The castle is solid and well-maintained; the bridge beside it carries considerable traffic between the Westmarch and the lands to the north.', '0b2e6a36edcefc06e5f110a065fd8a4b', ST_GeomFromText('POINT(6.583805 46.066796)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (452, 'Minas Thonfalon', 'ruins', 0, 'N/A', 'Minas Thonfalon is a ruined Arnorian watchtower on the ''Bog Coast'' of the Rast Vorn, built in T.A. 503 to watch traffic along the coast. Its foundations are slowly sinking into the waterlogged ground; the upper courses have already tumbled into the bog. On foggy days the broken tower is barely visible above the reed-beds, and local fishermen give it a wide berth.', '0d1123b21ecdf4915a1414dfbdc79bd8', ST_GeomFromText('POINT(-3.694613 47.422739)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (453, 'Annúminas', 'ruins', 0, 'N/A', 'Founded in 3396 by the High-king Elendil.. Royal seat of Arnor; locus of a Palantír; after T.A. 861 the capital of Arthedain.. Annúminas was the home of Arthedain''s Kings before the city was sacked in 1409, when the hordes of the Witch-king overran all the former lands of Arnor. Annúminas once held the position of the fairest of Dúnadan cities in the North, with broad, tree-lined avenues and graceful buildings of white marble. No wall surrounded the city, which was deemed a place of peace and learning. Scavengers have picked most of the ruins clean, but tales abound of sealed vaults underneath the library and the palace.', '0d8e3b9e2948db2be16c2f4956546265', ST_GeomFromText('POINT(-0.848949 53.010855)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (454, 'Cathiel', 'ruins', '', 'Ruined city. Cathiel was a settlement of Ethir Gwathló in Cardolan, about seventy-five miles inland from the mouths of the Gwathló. It had a population of roughly 4,000 in T.A. 250, declining through the Third Age and finally abandoned by T.A. 1640.', '0df0970789f98c362a31cfadb2b83153', ST_GeomFromText('POINT(-2.236776 47.126324)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (455, 'Haerlond', 'point of interest', '', 'A small harbour village in Andrast, its modest dock serving ships damaged rounding the dangerous cape. Beneath the village''s timber houses lie the buried ruins of an older Númenórean settlement, visible when the ground shifts. Sailors know Haerlond as a last refuge before the open sea; the villagers are skilled at patching hulls and provisioning vessels.', '0fefd0115eb8dc430522a1ee0368e24e', ST_GeomFromText('POINT(1.892833 40.529686)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (456, 'Calembel', 'fortified town', 1100, '100% Gondorian', 'Settled by Númenóreans in late Second Age, granted charter by Ostoher of Gondor in T.A. 488.. Provisioning the mining communities in the Ered Nimrais; seat for the Lord Protector of Lamedon.. Calembel is on the road which links central Gondor to the mining communities of the southern White Mountains.', '125192817421a689c47d02e86b8e7513', ST_GeomFromText('POINT(11.577131 43.689014)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (457, 'Bree', 'town', 410, '45% Stoor Hobbit, 50% Bree-man, 5% Dúnadan', 'Settled by migrating Dunmen in the early Second Age.. Collecting point for the products of surrounding farms; trading center due to its location at the junction of the Greenway and the Great East Road.. Bree is the largest town in Bree-land, a region of Arthedain that is peaceful, agricultural, and largely autonomous. The town is built around a large hill and is protected by a formidable dike surmounted by a thick hedge. Numerous smials, or Hobbit-holes, can be found in the flanks of Bree-hill. Both Men and Hobbits live in Bree, making it one of the few locations in Middle-earth where co-operation between folk of different races occurs. Due to its central location, Bree witnesses many strange folk passing through its streets, and the town is a perfect place to acquire or sell information.', '12861aa0bb58c19dd55228f70e240f6b', ST_GeomFromText('POINT(1.228323 51.560255)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (458, 'Greenholm', 'town', 310, 'Humans, Hobbits, Silvan Elves', 'A quiet outpost in the middle Third Age, home to a few Arthadan families coexisting with nearby Elves who observed the comings and goings of mortals on behalf of the lords of the Grey Havens. One of the Elves, Sinda Calenlinn, was an expert herbalist fond of fermented grains.', '13328700f334769383730b40c93d2add', ST_GeomFromText('POINT(-3.382751 51.39257)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (459, 'Enerond', 'ruins', 5, '', 'Ruined city. Enerond was a township of Brethyar in Arthedain, on the east bank of the Lune River. It had a population of about 5,100 in T.A. 250, declining through the Third Age until abandoned before its end.', '1529023a68b193b8bf5fbe78196b3d6e', ST_GeomFromText('POINT(-1.237397 52.950469)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (460, 'Lomost', 'fortress', 120, 'Gondor', 'Along with its sister fortress of Aerost, Lómost (''Echo Fortress'') is one of two critical coastal beacons defending Anfalas against Corsair raids. Built in T.A. 1634 after the Great Raid on Pelargir, it stands on the western Anfalas coast and can relay news of approaching enemies to Lond Galen or Annon Drúin within hours via its beacon tower. The fortress is a solid coastal structure of dark stone, battered by sea-wind; the garrison here is small but alert.', '1534c928808a039095dd49e5eb3d37b9', ST_GeomFromText('POINT(3.325376 40.91388)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (461, 'Ethring', 'fortified town', 1300, '95% Gondorian, 5% Dunnish', 'Settled by Gondorians in the late Second Age, granted a royal charter in T.A. 180.. A market town serving most agricultural and mining communities of Lamedon.. Ethring profits from the traffic along the Gondor Road.', '155d4c11e6dc874f9b09cb0dd0f37f1b', ST_GeomFromText('POINT(12.41734 43.320786)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (462, 'Fornost Erain', 'fortified city', 3100, '95% Dúnadan, 5% Mixed Mannish', 'Fornost Erain — the ''Fortress of the Kings'' — crowns a steep rise on the southern slopes of the North Downs, capital of Arthedain. It is as much fortress as city: concentric rings of stone walls enclose the royal palace, the great library, and the merchant quarters of the Dúnedain. The city''s streets are orderly and well-paved; the men who walk them are tall and grave-faced, with the bearing of a people who know themselves to be heirs of Númenór. Beyond the walls, the North Downs roll away in all directions.', '15ba230084a51abb21a6873b76a635a0', ST_GeomFromText('POINT(1.475915 53.015801)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (463, 'Galenros', 'point of interest', '', 'A tiny Elvish hamlet south of the spur of the Forered Luin — fifteen households of 41 Elves in total, a mixture of various kindreds. It was founded in the Second Age as a communal retreat by High Elven philosophers, artists and nature-lovers who sought refuge from the bustle of Mithlond. The settlement answers to Tawarobel for governance. A visitor finds a handful of delicate timber-and-stone houses half-hidden among the trees, connected by winding paths — an air of quietude and careful order marks everything here.', '1691e47321554c359e67eaa3f4b72b85', ST_GeomFromText('POINT(-6.386798 53.375535)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (464, 'Harlond', 'town', 500, '100% Gondorian', 'Settled soon after founding of Minas Anor, circa S.A. 3320.. The port for Minas Anor; oversees river traffic on Anduin.. Harlond is a busy town, handling almost all of the freight from southern Gondor bound for the lands of Calenardhon and Rhovanion.', '16cbb3fddb6eb25580cda7bcfc7f71e9', ST_GeomFromText('POINT(-8.135416 50.782548)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (465, 'Eithel Thurin', 'town', 620, '40% Gondorian, 60% Haradan', 'Eithel Thurin is a Gondorian garrison-town in Harondor, founded by the army in T.A. 932 to extend Gondor''s control over this contested coastal region. It serves as a trading centre for coastal traffic and the main base for Gondorian authority between the Poros and Harnen rivers. The town is frequently raided by Umbar and hostile Haradrim; its walls have been repaired many times, and the population has a watchful, embattled quality.', '1978c4880d101efe741d9f6709199d4f', ST_GeomFromText('POINT(13.750343 39.180084)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (466, 'Minas Arthor', 'city', 5000, 'Gondor', 'Minas Arthor, once the capital of Arnach, was situated at the crossings of the Erui, where a settlement had existed since the earliest chronicles. Founded at the beginning of the Third Age, it grew into the center of a prosperous agricultural district.', '19f01cb59625b48166dd6ffef0991750', ST_GeomFromText('POINT(16.769285 42.493854)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (467, 'Lond Rhaen', 'village', 120, '', 'A small fishing village on the northwestern coast of Andrast, sheltered in a safe bay of Rast Rhaen. A handful of stone-walled houses face the water; the people here are Dunir fisher-folk whose boats rarely venture far from the bay''s protection.', '1a056b5e31d35c42e643f9f716ee1b84', ST_GeomFromText('POINT(0.966925 39.862769)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, external_id, geom) VALUES (468, 'Mirimar', 'city', 560, '', '1a43bb9d28424d1c7a09348ba2f53e46', ST_GeomFromText('POINT(-10.308741 52.60319)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (469, 'Bar Astirian', 'manor', 20, '', 'Astorion Manor (S. Bâr Astorion) was the former home of House Astorion, a noble Gondorian family. It was situated on the outskirts of the Entwash Mouths, north of Min-Rimmon, where the family held extensive lands.', '1c4692f658908ed6ebfc090f4b3ab0a5', ST_GeomFromText('POINT(14.603374 45.026475)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (470, 'Ossarnen', 'fortified town', 1400, '85% Gondorian, 15% Dunnish', 'Ossarnen is a Gondorian mining town in the White Mountains, established in the Second Age and grown since. Its population works the mineral seams of the surrounding mountains; the settlement sits well off the main road, connected to it by a rough track. Stone houses and mine-head structures crowd the narrow valley floor; the sound of picks and hammers carries far in the clear mountain air.', '212b1c186141ab63909ccb43e5d88c00', ST_GeomFromText('POINT(11.391809 44.11232)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (471, 'Gram', 'dwarven mine', 1000, 'Orcs', 'The Witch-King''s servants erected this mountain fortress on the southern branch of the Misty Mountains forming the boundary of Nan Angmar. Gram was the most formidable Orc stronghold west of the mountains; no man had ever escaped its depths to give a coherent account of its interior.', '221d7d6f3912b1b81ab7b3186ce88fb3', ST_GeomFromText('POINT(7.71789 54.443782)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (472, 'Imladris', 'manor', 125, 'Mixed Elvish', 'Founded by Elrond Half-elven in S.A. 1697.. A haven for healing, learning, and the arts.. The house of Elrond Half-elven is located in a narrow ravine, not easily found in the broken lands of fallen Rhudaur.', '223f370e8996d2b428a5d4e5d6c21035', ST_GeomFromText('POINT(9.871206 51.52831)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (473, 'Tharbad', 'fortified town', 21345, '60% Cardolani, 20% Dunnish, 10% Northman, 5% Eriadoran, 5% Other Mannish', 'A Númenórean river port dating to the mid-Second Age.. A major urban hub; the effective administrative center of Cardolan; an outpost of Gondorian authority.. Since the fall of King Ostoher in T.A. 1410, the former Númenórean port of Tharbad has declined from the glory it held in ages past.', '22fe3e29220c0d9a82bfb2680d8b854a', ST_GeomFromText('POINT(3.094174 48.841242)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (474, 'Minas Ongoth', 'ruins', '', 'Minas Ongoth stands in ruin on its hilltop, its towers broken and its gates long rotted away. The site commands a good view of the surrounding country, which is probably why it was built here; now only the wind occupies it.', '235269a8e1723e126b7887d29c4fd341', ST_GeomFromText('POINT(-2.005377 54.129843)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (475, 'Bar Engui', 'village', 60, '', 'A small hamlet on the river Engui in Andrast, one of the most remote corners of Gondor. A handful of stone-walled garths cluster near the river; the people here are Dunir fishermen and small farmers who seldom see strangers.', '23a6ef21a52eb11823391f20df3fc5a7', ST_GeomFromText('POINT(-0.162456 40.376272)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (476, 'Athrad Poros', 'town', 450, '', 'The ford settlement of Athrad Poros was an important stop on the land trade route south. It began as a military garrison protecting the border between the nascent Kingdom-in-Exile and the Umbarean sphere of influence. When the Harnen Corridor opened, Athrad Poros became a critical juncture for trade with Near Harad and Khand.', '25d3ae62f10cbc7919506ae65fd7dd2c', ST_GeomFromText('POINT(18.127267 40.357852)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (477, 'Rood', 'village', 280, '70% Dúnadan, 30% Mixed Mannish', 'Grew around Baranduin river traffic in early Third Age.. A collecting point for area farms; a shipping station for freight on Baranduin.. With the sack of Annúminas, Rood began to fall into a decline, becoming a den for thieves and bandits.', '28a90db52bc32e64d25b3ba266dd7c80', ST_GeomFromText('POINT(0.44034 52.870134)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (478, 'Fangoth', 'ruins', '', 'Fangoth is a ruin now, its walls toppled and its streets empty. Once a city of some standing, it was abandoned after the troubles that plagued this region in the middle Third Age. Only broken archways and the outlines of old streets remain visible beneath the weeds.', '2ac39eaf2604ce7c7b5058e778f63624', ST_GeomFromText('POINT(0.92569 48.750512)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (479, 'Minas Tirith', 'fortified city', 25000, 'Gondor', 'Originally called Minas Anor (S. Tower of the Sun), Minas Tirith was built at the foot of Mount Mindolluin in the Ered Nimrais. The city rose in seven concentric tiers of white stone, each gate offset from the last, and the White Tower housed the last Palantír in Gondor''s keeping. Together with Osgiliath and Minas Ithil, it formed the core of Gondor.', '2c1d9a8d2a5d1ab62942438dfd375a62', ST_GeomFromText('POINT(17.422569 43.158864)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (480, 'Tir Feren', 'castle', 80, 'Gondor', 'A Gondorian castle overlooking Parth Feren in the westernmost Pinnath Gelin. Built of local stone, it commands the beechwood hills that give it its name (''Beech-ward''). A small garrison and the lord''s household maintain the castle; the surrounding parkland of old beeches is peaceful in summer but exposed to the sea-wind in winter.', '2ca07fa0e4327709a553cdaef455adce', ST_GeomFromText('POINT(2.740454 41.548916)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (481, 'Car Gaul', 'manor', 30, '', 'A freehold estate in the County of Nan Lefnui, on the lower Lefnui. It is the property of the Bannor family, who farm the surrounding fields and pastures of this remote corner of Gondor''s western frontier. The manor house is a solid stone farmstead with a small courtyard and stableyard.', '2cfbecb372b043aee8f642cd6a7b86ed', ST_GeomFromText('POINT(1.549864 42.010386)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (482, 'Mithlond', 'city', 2200, '50% Silvan Elvish, 40% Sinda, 10% Noldo', 'Mithlond — the Grey Havens — comprises two harbours at the end of the Gulf of Lhûn: Mithannúnlond on the west shore and Mithrónalond on the east. Founded by Círdan after the drowning of Beleriand, it is the principal Elvish settlement in the west of Middle-earth, a place of shipbuilding and of departure for those sailing to the Undying Lands. Its stone quays are graceful and always busy with some quiet Elvish industry; tall ships lie at anchor in the fjord, their white sails furled.', '2d63757ee0677b0d14e6ef15cf80e497', ST_GeomFromText('POINT(-5.813533 51.636483)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (483, 'Linhir', 'city', 4100, '95% Gondorian, 5% Mixed Mannish', 'Founded by Anárion in S.A. 3421.. A port and center for trade and manufacturing, situated at the point where the Gondor Road crosses the Gilrain.. Linhir is prosperous and busy, and a large population of unseemly characters has grown to prey upon the weak and gullible.', '2f80c0f3f97fa5120648aac455745217', ST_GeomFromText('POINT(13.13929 41.259747)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (484, 'Bar-i-Dinuviel', 'point of interest', 244, 'Noldor', 'Bar-i-Dinuviel (S. Home of the Nightingale; Os. Mbar Tinduvela) was a fishing village on the coast of Dor Tinuviel.', '2fb7c7e28436f4bd9c61816182aed529', ST_GeomFromText('POINT(-7.395721 48.731791)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (485, 'Edoras', 'city', 1600, 'Rohirrim', 'Edoras (R. The Courts) was the capital of Rohan, built upon an ancient hill site at the northern edge of the White Mountains. The great hall Meduseld crowned the hill, and the kings of the Mark were buried in twin rows of barrows outside the main gate. The surrounding treeless plains gave its lookouts a commanding view of all approaches.', '3111faba40b284fcb721cbdcf31ac234', ST_GeomFromText('POINT(9.385098 45.345745)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (486, 'Firaen', 'ruins', '', 'Firaen is a ghost of a settlement — crumbling walls, collapsed rooftops, and silence. Whatever community lived here was driven away or died out long ago, and nature has been slowly reclaiming the stone ever since.', '3176e8d194093b2c5dc2ae99f1343b86', ST_GeomFromText('POINT(-3.695985 53.387085)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (487, 'Litash', 'town', 3400, '95% Angmarean (Mixed Mannish), 5% Orc', 'Litash guards the eastern approaches to Angmar from its position at the mountain''s foot, garrisoned by a large force of the Witch-king''s mixed Mannish troops. A training centre for priests of the Dark Religion and a base for tax-collection in eastern Angmar, it is a grim town of barracks and ritual halls. The priests who walk its streets wear dark robes; the ordinary soldiers are rough and watchful. Travellers approaching from the east are stopped and questioned before being allowed to pass.', '31a29acf8ccc956ecf4321750e626859', ST_GeomFromText('POINT(9.489663 54.634588)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (488, 'Lond Daer', 'ruins', 0, 'N/A', 'Established as a colony of Númenor by Aldarion in the ninth century of the Second Age.. A Númenórean haven on the shores of Endor.. Lond Daer was ruined by a cataclysmic tidal wave in S.A. 3319.', '32ec88080dbad7aa7fa3312e02d2fd8e', ST_GeomFromText('POINT(-0.911886 46.925789)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, external_id, geom) VALUES (489, 'Himihiril', 'castle', 50, 'Gondor', '330a8f4cdc4243eab59df18dc11bc301', ST_GeomFromText('POINT(-3.212527 54.57971)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (490, 'Woodmen Village', 'town', 200, 'Woodmen', 'A small village of the Woodmen in the Upper Anduin Vales, partially built on large platforms in the trees in the Elven fashion, reflecting the friendly relations between the Woodmen and the nearby Wood-Elves.', '33776f6e655140f9d3dcf37a1f809675', ST_GeomFromText('POINT(16.365852 51.231894)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, external_id, geom) VALUES (491, 'Turonost', 'city', 890, 'Noldor', '364708d6d5fa3c5222b7232ac0755ec8', ST_GeomFromText('POINT(-11.932362 55.033719)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (492, 'Arailt', 'fortress', 120, 'Dunlendings', 'Arailt Hold was the ancient seat of the Dunlending Arailt clan. By the time of the War of the Ring it had long been abandoned; the Rohirrim had established a scouting camp above the ruins and nearby caves.', '39a1fb6f2b80d2adcf19c573d6e18ad2', ST_GeomFromText('POINT(6.432063 47.021704)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (493, 'Cerin Amroth', 'keep', 40, '15% Sinda, 85% Silvan', 'Cerin Amroth is a grass-covered hill in the heart of Lórien, crowned by two concentric rings of trees — one of niphredil, one of elanor — whose flowers bloom in gold and white all year. It was designed as a royal retreat by King Amroth and served as the palace of Lothlórien for ages. The traveller allowed inside Lórien finds the hill astonishingly beautiful; the light here is unlike that of the world outside, clear and golden even in winter.', '3a0e8f7057a10fdba04997b4c64e5c03', ST_GeomFromText('POINT(12.115104 49.415377)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (494, 'Fennas Drunnin', 'town', 430, '', 'A Council directed most affairs in Fennas Drúnin, a town that depended on local farms and vineyards for its prosperity. Some Hobbits lived nearby but generally avoided contact with the townspeople. Far from the main roads of Cardolan, it was a good base for anyone wishing to explore southern Rhudaur or the Elven ruins of Eregion.', '3a6a1f51e11f666f2597c738833772d8', ST_GeomFromText('POINT(5.871737 50.178819)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (495, 'Herubar Gûlar', 'castle', 0, 'N/A', 'Herubar Gûlar is a keep of uncertain origin — possibly Númenórean — on the Mitheithel, controlling traffic along and across the river. Its age means its stonework is of high quality, but it has clearly changed hands many times; the current arrangements inside are rough and military. The keep is reputed to be haunted by the spirits of previous garrisons, and the soldiers stationed here are uneasy in the lower levels.', '3b0b65c60127a330e405a5e4f60c6590', ST_GeomFromText('POINT(7.128556 52.04951)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, external_id, geom) VALUES (496, 'Mindolhendi', 'city', 900, '', '3d368f4dc9bafeeb9ae34a63791ffd66', ST_GeomFromText('POINT(-8.571719 55.929858)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (497, 'Eredimar', 'village', 92, 'Silvan Elves, Dwarves, Men, Hobbits', 'Eredimar (S. Mountain Home) lay at the foot of the Ered Luin within the valley of Imladorn (S. The Wooded Valley). Despite housing fewer than 100 people, it was remarkable for its cultural diversity — Hobbits, Dwarves, Elves, and Men had all settled here at various times. Sulfur springs nearby gave Eredimar renown as a place of healing, and three well-maintained lodges welcomed travelers.', '3d50c595ccaa0ae4f93d96ce0dd050c6', ST_GeomFromText('POINT(-7.199672 52.568257)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (498, 'Filimer', 'ruins', '', 'Filimer lies in silent ruin, its crumbled walls barely distinguishable from the surrounding landscape. Locals say it was once a settlement of some size, but no record survives of who built it or when it fell. Travellers passing through see only broken stone half-swallowed by grass and thorny scrub.', '3d84453a5c46f62464fcb2edc61b25e1', ST_GeomFromText('POINT(4.034143 49.498538)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (499, 'Bar Irlossiel', 'ruins', '', 'Ruined castle. Barad Perinluoss, commonly known as the Silent Castle, was an ancient Elven refuge in southern Sîrgala — an independent community of Wood-Elves and Arthadan religious refugees who pledged fealty to a half-Elf known as Iralussiel the Tranquil. Iralussiel died mysteriously around the 11th or 12th century T.A., and the shelter became eerily peaceful thereafter.', '3df2661c13cb9ec080b86da4f7a5298b', ST_GeomFromText('POINT(-1.862215 50.200255)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (500, 'Methrast', 'tower', 87, 'Gondor', 'Methrast is the southernmost cape of the Belfalas peninsula — sheer, unclimbable cliffs and dangerous shoals that only the most skilled pilots dare approach by sea. The cape also marks one terminus of the Belfalas coastal beacon system; news of approaching enemies sighted here can reach Dol Amroth in hours. Seals sun themselves on the rocky shores below. There is no settlement at the cape itself, only a small watch-post.', '4106d605bd81fc06a53f32b824e5e37a', ST_GeomFromText('POINT(10.279651 39.454845)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (501, 'Nan i Naugrim', 'dwarven mine', 430, '', 'The greatest mine of Nan-i-Naugrim and the capital of the Broadbeam Dwarves since the Second Age. By the mid-Third Age, Edennogrod — the largely ruined Khazad above Nan-i-Naugrim — stood as a shadow of its former self. At the end of the Third Age it was ruled by the feudal lord Grár, who held the honorary title Mountain King among the Shire-folk.', '4291252739bbc7141616918bcaba22ad', ST_GeomFromText('POINT(-7.108307 54.632519)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (504, 'Minas Girithlin', 'castle', 60, '70% Cardolani, 20% Eriadoran, 10% Dunnish', 'Minas Girithlin is a stout castle set in the hills, ancestral home of the Princes of Dol Girithlin, built around T.A. 590 to dominate the surrounding countryside. Its walls have withstood several sieges without being breached; the garrison is loyal and experienced. The Prince''s hall within is comfortable if not luxurious — a working noble''s house, with stables and a well-stocked armoury.', '440c871cf631fbad125559f4e3d7fcea', ST_GeomFromText('POINT(-2.625009 48.761944)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (505, 'Bar Adorn', 'town', 600, '', 'Bar Adorn was a settlement on the River Adorn near the western borders of Rohan, serving as a minor trading post between the Rohirrim and the Dunlendings of the region.', '443fc38145c4ef1c1899d04d3d02ce4d', ST_GeomFromText('POINT(3.388161 46.091757)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (506, 'Saerthondost', 'fortress', 200, 'Gondor', 'Saerthondost was one of two Dúnedain strongholds protecting Pinnath Gelin and Nan Lefnui from the wilds of Hairaverkien. Located on the north bank of the Lefnui where the river turned sharply northwest, it was named for the nearby swamps rich in shepherd''s herbs. A lighthouse tower linked it to its sister fortress Pinnornost to the northeast; it was founded in T.A. 823 and abandoned in T.A. 2157.', '46d9ea208b4d78d838a35cbfe57ccc5f', ST_GeomFromText('POINT(3.287055 42.466171)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (507, 'Calenhad', 'watchtower', 90, '100% Gondorian', 'Ordered built in T.A. 491 by Gondor''s King on the site of an earlier signal-platform.. Communications in northern Gondor.. Calenhad is the sixth beacon in the chain stretching from Minas Anor to the northwest.', '476fb6b7cd1817b7359c8b8c58e1a266', ST_GeomFromText('POINT(14.264176 44.278558)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (508, 'Adavalinda', 'village', 140, '', 'A small village on the eastern bank of the Lefnui, where the river meets the Rámanen confluence. It serves as a staging point for travellers seeking to cross the White Mountains via the Cirith Iaur, some forty miles to the northwest. A ferry here is the last easy crossing before the river narrows to flat-bottomed-boat country upstream. Stone and timber houses cluster around the landing, their occupants largely dependent on guiding travellers and working the river.', '481a34f0a4593aa08c7b358c62091a35', ST_GeomFromText('POINT(1.378078 41.886452)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (509, 'Cargash', 'watchtower', 50, '100% Angmarean (Mixed Mannish)', 'Built by Witch-king, ca. T.A. 1400.. Designed to give the Witch-king warning of trespassers and a base from which to strike at Arthedain.. Regular patrols depart from Mindil Cargash to sweep En Udanoriath which lies between Angmar and Arthedain.', '482aba99e3d5973b8398277777044585', ST_GeomFromText('POINT(5.813279 54.991128)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (510, 'Thingastathbaurg', 'town', 150, 'Woodmen', 'A village of the Woodmen in the Upper Anduin Vales, the name meaning ''Assembly-Place Fort'' in Rhovanion. Its timber longhouses and stockaded hall sit in a forest clearing; the Woodmen here are sturdy folk who live by hunting, forestry and small farming. The great trees of Mirkwood are close by; the village is self-reliant and watchful.', '48d6956a9e549bdf8867e069a7424d2c', ST_GeomFromText('POINT(13.723291 53.101593)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (511, 'Minas Ithil', 'fortified city', 30000, '90% Gondorian, 10% Mixed Mannish', 'Founded by Isildur in S.A. 3320, rebuilt in T.A. 1.. Control of the passes into Mordor; garrison for Gondor''s army in Ithilien; location of a Palantír.. Minas Ithil is a Gondorian city protected by a deep valley in the Ephel Dúath.', '4935db7004ad27dfe5c8740008ea1b23', ST_GeomFromText('POINT(18.905247 43.528463)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (512, 'Michel Delving', 'town', 650, '45% Harfoot, 30% Stoor, 25% Fallohide', 'Michel Delving is the largest town and administrative capital of the Shire, spread across the gentle slopes of the White Downs in the Westfarthing. The Mayor''s Hall and the Mathom-house — a repository of Hobbit curiosities — are its two most notable buildings. Most houses are of whitewashed stone with round doors and windows; kitchen gardens and flower beds line every lane. Market day is the social high point of the week, drawing Hobbits from the surrounding villages to sell produce and catch up on news.', '493a02d2bcbd0fb36907edb7ea0eecaf', ST_GeomFromText('POINT(-2.454585 51.363869)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (513, 'Vidusbaurg', 'town', 520, 'Northmen', 'Buhr Widu, situated near the small Forest Lake, retained some of the royal splendor of the days of Vidugavia. The Grammuz princes who ruled it after the Plague lacked the strength to restore its former glory. Like most Northman villages on the plains, it consisted of long wooden and thatched houses defended by an earthen wall and sturdy wooden towers.', '4a24da5b5ac1a6c3fb9cdd15d503819f', ST_GeomFromText('POINT(20.2981 50.405638)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (514, 'Morkai', 'castle', 1000, '100% Angmarean (Mixed Mannish)', 'Barad Morkai rises from a granite bluff above the Angmar Road — a black-stone fortress built by the Witch-king to monitor all movement entering and leaving the Nan Angmar. The road passes directly beneath its walls; travellers feel the weight of the fortress''s watch as they pass. A large garrison occupies it permanently; the broad plains to the south serve as Orc training grounds.', '4be9468f854fa8a1dcb64764ace32902', ST_GeomFromText('POINT(6.60636 55.068171)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (515, 'Faranel', 'ruins', '', 'Faranel is a ruined city in the northern lands, its once-inhabited quarters now exposed to wind and rain. The scale of the ruins suggests a sizeable population at its height; by the mid-Third Age there is not a single inhabited building remaining.', '5011afade619f3d35e1d667cfb0f6f69', ST_GeomFromText('POINT(-1.381329 54.563073)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (517, 'Bar Morthil', 'point of interest', 'Dúnedain', 'A royal estate at the westernmost tip of Andrast — the farthest habitation in all of Gondor. A single stone manor overlooks the sheer sea-cliffs of Ras Morthil, where the ocean crashes hundreds of feet below. The estate is maintained year-round by a warden and servants; it faces west toward the open sea, built by the sons of Elendil as a memorial to drowned Númenór. Kings and Stewards sometimes come here for solitude.', '556e0b805bb4afe0be501c6fb7924f5e', ST_GeomFromText('POINT(-3.144798 39.274599)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (518, 'Tilmendir', 'castle', 140, '70% Gondorian, 30% Dunnish', 'Built by Gondor, circa T.A. 991.. Surveillance of traffic passing from Westmarch to Anfalas; a show of authority for the local Dunnish tribes.. Tilmendir is located ten miles south of the town Derwath.', '5782c24e1c9a90bd8ae93a0624d9e87d', ST_GeomFromText('POINT(6.214492 45.163506)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (521, 'Guinnion', 'ruins', '', 'The village of Guinnion has long since been abandoned — a scattering of mossy foundation stones and choked lanes where a small community once lived. The site lies quietly off the road, overlooked by all but the most curious travellers.', '59cf3830ff27cef7e73d05bbe03b3805', ST_GeomFromText('POINT(-1.168778 47.430766)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (522, 'Bodroth', 'city', 0, '', 'Bodroth was a city of Eketyar in Arthedain, situated on the northern shores of Lake Evendim about forty miles north of Annúminas. It had a population of roughly 4,900 in T.A. 250, but declined through the Third Age and was eventually abandoned, though it survived the fall of the last King by several generations.', '5abbd6f333ee1250e91efc4a02013c02', ST_GeomFromText('POINT(-1.098611 53.3107)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (523, 'Culwic', 'village', 400, 'Gondor, Dwarves', 'Culwic, originally known as Himtil or Himobel (S. Chill Village) and later as Colwich, was a small town in western Arthedain on the Little Lune, just north of the borders of Dor Lelvin and Lindon. Its mixed population of Men and Dwarves supported the dwarven settlements to the north through industry and agriculture.', '5cbba5e7606045d742bbfc0cd65aa0b1', ST_GeomFromText('POINT(-6.450549 53.936333)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (525, 'Cirith Dudhrandir', 'town', 450, '', 'Cirith Dudhrandir was the only major mountain pass through the Belfalas Peninsula and the only one with a paved road, making it strategically vital for Gondor''s southern defenses. At 5,800 feet and over sixty miles east to west, it was guarded by the fortress of Naur Amrûn. The pass was named in S.A. 3400 when Edhelion of Eldalonde received Belfalas as a fief.', '5ee93f5bc3e4001805d234e95a79657d', ST_GeomFromText('POINT(10.161853 41.049572)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (526, 'Anghul', 'castle', 80, 'Sauron', 'Anghul (''Iron-wind'' in Sindarin) is one of the six great fortresses of Angmar, situated on a hill above the Anghir below the escarpment of Nan Angmar. It broods over the Anghir Vale and controls the No Man''s Land. A garrison of 300 men watches for spies; the commander is one of the Witch-king''s Ashâktur. Dark stone walls; the wind off the escarpment is bitter and constant. The Black Raven on Red is the garrison''s banner.', '5f7b31b1e45bc32f9710965931ec02be', ST_GeomFromText('POINT(5.880489 55.633701)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (527, 'Forlond', 'town', 840, '50% Silvan Elvish, 40% Sinda, 10% Noldo', 'Forlond is the southern Elvish haven of Lindon, hidden at the head of a steep fjord on the eastern shore of the Gulf of Lhûn. Founded after the ruin of Beleriand, it is primarily a shipbuilding settlement — the sound of hammers on timber and caulking mallets is heard on every visit. The Elves here are of mixed kindred and more accustomed to mortal visitors than most Elvish settlements, though the haven is not on any road and is difficult to find.', '60d41486e9354c4d4dd2445e69e812e8', ST_GeomFromText('POINT(-9.783386 52.192311)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (528, 'Rildolach', 'ruins', '', 'Rildolach lies in ruin among the hills, its old streets grown over. Travellers who venture close enough to see it clearly describe a settlement of Arnorian-era stonework, collapsed and overgrown, with no inhabitants and no sign of recent occupation.', '62529e65a017f5026aa81f71c3acec85', ST_GeomFromText('POINT(-3.902661 53.717587)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (529, 'Malehaut', 'village', 45, '', 'A coastal Eriadorian town of Fonntir in Minhiriath, known as Atem (''fathom'') or Carmalehaute (''Malehaut''s town'') in Dunnish. By T.A. 2740 it had a population of some 2,700 — a working port with fishermen, traders and those who live by the sea''s rhythms.', '62ee9d110b26b1dfee272ff8634879da', ST_GeomFromText('POINT(-3.251467 47.012628)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (530, 'Iant Methed', 'point of interest', 5, '', 'Iant Methed (The Last Bridge) was built of stone with three great arches at the height of Arnorian power in T.A. 320. In the petty wars of Rhudaur the crossing was generally considered neutral ground. The Last Inn, long run by the Grumm family, stood nearby; just northwest lay the ruins of Dol Elerilde, stronghold of an old lord of Rhudaur.', '6442aa8e9dbeb487c3a787e44786eb05', ST_GeomFromText('POINT(6.656038 51.505654)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (531, 'Laur Dunnen', 'town', 420, '', 'Larach Duhnnan lay on territory of Clan Feargan but the flow of foreign traffic made it a neutral ground for inter-tribal discussions and trade. It had no walls, relying on the nearby Feargan fortress for defense, and sat at one of the few accessible crossings of the Dunstrem, for which the clan lords charged a modest toll.', '650c99a437e0cce7a326674897da17d6', ST_GeomFromText('POINT(4.330594 47.761037)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (532, 'Aerost', 'fortress', 300, 'Gondor', 'A coastal fortress on the Rathon Gondor in Anfalas, some forty miles west of Lond Galen. Built after the Great Raid on Pelargir (T.A. 1634) to defend the coast between the Celgalen and the Lefnui, Aerost is a key link in Anfalas''s chain of coastal beacon towers. From its walls, watchmen can warn neighbouring settlements of Corsair raids within hours. The fort''s stone battlements are weathered by salt wind, and a small settlement of soldiers and their families huddles in its shadow.', '65907bd900d495733194dcf01f5f1dde', ST_GeomFromText('POINT(3.626902 41.034679)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (533, 'Talsir', 'town', 250, '', 'Talsir was one of the free cities of Cardolan on the west bank of the Gwathló, about 170 miles downstream from Tharbad. With a population of roughly 4,300 in T.A. 250, it was an important river stop and one of the few settlements of ancient Minhiriath to survive into the late Third Age.', '67efb3b67cdd1b2fd62ecb938e847972', ST_GeomFromText('POINT(-0.234818 47.538839)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (534, 'Framsburg', 'city', 340, 'Northmen', 'Wraecaburg, though not directly under the Witch-King''s rule, suffered frequent attacks and harbored many unsavory characters from outside Rhovanion. Its men occasionally traded with kinsmen at Maethelburg, but relations grew increasingly suspicious over time.', '681965fb86a89207792118ea20e07ff9', ST_GeomFromText('POINT(14.009562 54.17404)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (535, 'Amon Sûl', 'ruins', 0, 'N/A', 'Originally built by Elendil in the Second Age.. Repository for a Palantír; later served as a landmark at the juncture of the three Kingdoms of the North.. From this vantage point, one has an excellent view of the Great East Road as it heads towards Rhudaur. For this reason, the hill served as a strategic focus for western Arthedain and Cardolan and has a long history of conflict surrounding it. The tower of Amon Sûl once held Palantír, which was removed to Fornost following the invasion by Angmar in T.A. 1409.', '68bdd7527815b3a3996d6fe4a7ffc0d4', ST_GeomFromText('POINT(3.521455 51.600639)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (536, 'Caras Galadhon', 'city', 800, '60% Silvan, 35% Sinda, 5% Noldo', 'Caras Galadhon is the city of the Galadhrim in the heart of Lórien, built as a network of interconnected flets on the massive trunks of mallorn trees. Designed by Galadriel, it rises tier upon tier through the golden canopy; the highest flets look out over a sea of leaves lit from within by the light that never quite matches the light of the world outside. Mortals who enter feel simultaneously welcomed and observed; the city is safe but its beauty is unsettling.', '6bbb1c408a02daac53e41d565a15fea4', ST_GeomFromText('POINT(12.542319 49.212858)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (538, 'Endrist', 'ruins', '', 'Endrist was once a township of the highland region, but by the mid-Third Age its population had long since gone. The foundations and a few stretches of wall are all that remain — a quiet ruin avoided by those who know its history.', '6e182f410f716a021ddf51be662a827d', ST_GeomFromText('POINT(-3.934113 50.51091)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (539, 'Annulond', 'city', 1200, 'Gondor', 'The principal town of Pinnath Gelin, set at the tip of a tongue of land where a stream from the Ram Galen joins the Lefnui. The folk of Annúlond maintain the only bridge spanning the Lefnui in this region. The town is modest but orderly: small stone houses of one or two storeys line the streets, and the lieutenant-Cáno''s large house stands beside the open main square that slopes down to the river wharf. Since the area lies in Gondor''s peaceful interior, no town wall was ever built. Outside the walls, the Knight of Annúlond''s manor overlooks liegemen''s farms and tenant plots.', '7019dd7f9f38eca5ad9f1305d1aec81b', ST_GeomFromText('POINT(1.770028 41.004206)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (540, 'Gamwich', 'village', 120, '50% Harfoot, 30% Stoor, 20% Fallohide', 'Settled during the migration of Hobbits into the Shire, T.A. 1601-1610.. An agricultural community.. Gamwich is the Westron translation of the Kuduk name Galabas.', '703e799a1608a3b9ff4ba4d98bf4f5bd', ST_GeomFromText('POINT(-3.155729 52.02727)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (542, 'Bar Nevedui', 'castle', 600, 'Gondor', 'A modest castle of southern Andrast on the river Nevduin, part of the remote county of Bar Morthil. Its walls are of local grey stone, maintained by a small household garrison; the surrounding land is sparsely farmed by Dunir dependants who provide the fort with supplies in exchange for protection from Corsair raiders.', '72157ca5d66a0573a56b3e8a6faabf35', ST_GeomFromText('POINT(-2.29744 39.175898)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (543, 'Lorilad', 'village', 89, '', 'Lórilad was a fortified village of Lebennin, situated in the Ethir Anduin roughly seventy-five miles downstream from Pelargir, halfway between Pelargir and the western cape of Lebennin.', '737cd8e5ebf3e66dbf23ade112de8011', ST_GeomFromText('POINT(14.580513 40.790865)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (544, 'Sindbar', 'town', 540, 'Gondor', 'A small Gondorian town near the westernmost eaves of Drúadan Forest, about eight miles north of Mount Nardol. Its stone houses and quiet market serve the scattered farms and woodcutters of the area. The Drúadan Forest nearby is avoided by most travellers; the Woses are seldom seen but always suspected to be watching.', '75990a293755b179f5736ad958400efe', ST_GeomFromText('POINT(16.166696 44.061143)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (545, 'Larad', 'ruins', '', 'Larad is a ruin on the edge of a river — the remains of a once-inhabited city now silent and empty. Its stone walls have partly fallen; the streets are overgrown and the only visitors are the occasional shepherd sheltering from rain.', '76dfe74b025986ac0f4ebb77b57d9539', ST_GeomFromText('POINT(-4.625452 55.090882)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (546, 'Sackville', 'village', 110, '50% Stoor, 45% Harfoot, 5% Fallohide', 'Settled during the migration to the Shire, 1601-1610.. Agriculture.. Proximity to the rugged Men of Eriador''s Red Hills bestows a reputation for crudity upon the residents of Sackville.', '77d37e506c88125d784b139a91d2b8c5', ST_GeomFromText('POINT(-1.551914 50.704271)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (547, 'Amon Dîn', 'watchtower', 120, '100% Gondorian', 'Construction of a signal-platform ordered in S.A. 3325 by Anárion of Gondor. Upgraded in the fifth century of the Third Age.. Part of Gondor''s northern communications network.. Amon Dîn was the first, counting from east to west, in a chain of seven beacon-towers. Its watch-fire relayed warning to Minas Anor of any attack on Gondor''s northern frontiers.', '7c9213e731d938b81aea872e8df58c2b', ST_GeomFromText('POINT(17.414725 43.745926)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (548, 'Buzdum Mazar', 'dwarven mine', 490, 'Dwarves', 'The greatest mine of Nan-i-Naugrim and the capital of the Broadbeam Dwarves since the Second Age. By the mid-Third Age, Edennogrod — the largely ruined Khazad above Nan-i-Naugrim — dominated the area. At the end of the Third Age it was governed by the feudal lord Grár, who bore the honorary title Mountain King among the Shire-folk.', '7ca62dfc23b7be2ef8254d8924249fdc', ST_GeomFromText('POINT(-7.283618 54.590338)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (549, 'Minas Brethil', 'city', 3000, '', 'Minas Brethil (S. Silver Birch Tower), capital of Celossien, was situated in the upper Serni valley and served as an agricultural center between the Glinduin and Serni rivers. After the Kin-strife it held some 4,000 inhabitants, a number halved by the Great Plague and only slowly recovered thereafter.', '7df88f8d7e3218d96af25370a52d4ce1', ST_GeomFromText('POINT(15.13078 42.223616)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (550, 'Cithrenor', 'ruins', 12, '', 'Cithrenor is a ruined town, its streets grown over and its buildings collapsed to waist-height piles of dressed stone. A handful of travellers camp here when they must, but the place carries an atmosphere of abandonment that discourages lingering.', '8047934e8120045a7dfdd987a70b4a80', ST_GeomFromText('POINT(-3.529856 49.026391)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (551, 'Maegoth', 'ruins', '', 'Maegoth was a city once, but the traveller finds only rubble. Crumbling walls, broken towers and overgrown foundations stretch for some distance across the hillside — a reminder of a time when this region was more populous and prosperous.', '8092b4e9ff96ef0fca43812a665b6a64', ST_GeomFromText('POINT(-1.537858 53.032579)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (552, 'Barad Eldanar', 'castle', 400, 'Sauron', 'An ancient Arnorian castle on the eastern edge of the Dyr Úvadan, ancestral home of House Eldanar — one of Elendil''s Faithful. One of the oldest Númenórean fortifications in northwestern Middle-earth. By c. T.A. 1325, the Angmarim seized it; the rightful lord Elenuil escaped through a secret tunnel and the family has dwelt in Fornost since. A well-armed Angmarim garrison now holds the walls.', '83b667b645b766f8d319f13ce83d8ca3', ST_GeomFromText('POINT(5.714704 54.61147)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (553, 'Enerond', 'ruins', 120, 'Gondor', 'Enerond is a ruined city on the east bank of the Lune, its stone buildings fallen and its population long since gone. It declined steadily through the Third Age; by T.A. 2050 there is not a soul living among the old walls.', '847e48fd06a77bc060eecf08013ec386', ST_GeomFromText('POINT(-4.803929 54.812309)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (554, 'Haerlond', 'town', 390, '60% Gondorian, 40% Dunnish', 'Haerlond is a small Gondorian harbour-town at the tip of Andrast, its modest dock serving ships damaged rounding the treacherous cape. Originally a Númenórean settlement of the Second Age, it received a royal charter from King Turambar in T.A. 602. The fishermen here are skilled at patching hulls and provisioning storm-battered vessels; their village is small and windswept, with whitewashed walls and a single street running down to the landing.', '850a1cb58a471a45f6dc25bffa830125', ST_GeomFromText('POINT(-2.935146 38.976766)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (555, 'Fanduin', 'city', 500, '', 'Fanduin had a fairly large population of 4,100 in T.A. 250, but its numbers declined through the middle Third Age and the settlement was eventually abandoned before the end of the Third Age.', '8606fc2022212421702bfc7856e27660', ST_GeomFromText('POINT(0.618315 52.568654)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (556, 'Pelargir', 'fortified city', 2500, 'Gondor', 'Pelargir (S. Garth of Royal Ships) was founded by the Faithful of Númenor in S.A. 2350 and became the chief harbour and oldest city of Gondor, built on the Anduin at the mouth of the Sirith. It served as the base of Gondor''s great fleet and was the kingdom''s primary port of trade, second city only to Minas Tirith.', '880eec93a3c2b8ebcf3a15446efc8c72', ST_GeomFromText('POINT(16.156195 41.256614)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (557, 'Metraith', 'town', 340, '70% Cardolani, 30% Eriadoran', 'Founded by Tarcil of Arnor as a summer residence, T.A. 514.. Seat of the Lords of Dol Tinare; a supply center and minor market for traffic on the Greenway.. The Princes of Tinare inhabit a large and crumbling mansion in Metraith.', '8a30ed251c814ab07981a8f8297d81f0', ST_GeomFromText('POINT(1.30749 49.536729)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (558, 'Endil', 'watchtower', 24, '100% Gondorian', 'Endil is one of the chain of watch-towers maintained by the Prince of Dor-en-Ernil along the Belfalas coast, built by Anárion in the Second Age to warn of pirates and raiders. Its light is visible from ships approaching the rocky shoals; the signal is relayed along the chain to Dol Amroth within minutes. The garrison is small — a handful of men — but their position commands the most exposed stretch of the Belfalas coast.', '8c148f9d1af8d5cf47a5659fc57cb055', ST_GeomFromText('POINT(9.822337 40.148109)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (559, 'Tir Eiliant', 'manor', 30, 'Gondor', 'The lordly seat of Anfalas, traditional home of the provincial governor (Cáno). A stone manor house and associated buildings in a defensible position overlooking Anfalas; the Cáno''s household and administrative staff maintain it as the principal seat of authority for the coastal plain.', '8db29c09f4bbb933338abeb89a583e7a', ST_GeomFromText('POINT(1.927719 41.294802)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (560, 'Archet', 'village', 100, '80% Bree-men (Northman/Dunnish Mix), 20% Stoor Hobbit (Kuduk)', 'Archet lies on the edge of the Chetwood in Bree-land, founded by settlers from the main Bree community in T.A. 1420. It is a purely agricultural village, devoted to growing grain and vegetables for the local market. Low stone-and-timber farmhouses face the road; the Chetwood stands dark and close to the east. Archet folk are generally more suspicious of strangers than Bree itself, and the village has a quiet, self-contained character.', '8ded0d2f712cc9da8128283409069cd1', ST_GeomFromText('POINT(1.345125 51.628198)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (562, 'Gundabad', 'dwarven mine', 2400, 'Orcs', 'Mount Gundabad was a sacred site of the Dwarves and an important enclave in the northern Misty Mountains. It was seized by Orcs multiple times and eventually became the capital of the northern Orc-realm, a constant threat to the free peoples of the north.', '8f218bbd2ef709fe97a98279b6093117', ST_GeomFromText('POINT(11.477501 54.99107)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (563, 'Caras Celairnen', 'town', 400, '85% Dúnadan, 15% Riverman', 'First settled around T.A. 740.. A regional market town in southwestern Arthedain.. Caras Celairnen is the westernmost center of purely Dúnadan culture in the North.', '8f5a68e82d9b9a94bfb81074f2fb2e3a', ST_GeomFromText('POINT(-3.759837 52.927546)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (564, 'Nadior', 'ruins', '', 'Ruined city. Nadior was a settlement of Ethir Gwathló in Cardolan, in a small bay on the Minhiriath coast about seventy miles west of the Gwathló mouths. It had a population of roughly 4,900 in T.A. 250, declining through the mid-Third Age until finally abandoned by T.A. 1640.', '9254774f94d07810d84b2ef9222dec09', ST_GeomFromText('POINT(-2.601318 46.65052)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (565, 'Fanuilond', 'town', 750, '100% Gondorian', 'Fanuilond is a Gondorian fishing village on the Ethir Anduin, occupied continuously since the early Third Age and repeatedly targeted by Corsair raids. Its prime location at the mouth of the Anduin keeps drawing people back despite the danger; the fishermen here are experienced and tough, and the harbour — though small — handles a surprising volume of river trade. The town''s walls have been rebuilt more than once.', '92d9b509c5a7e1e5217182f663f52897', ST_GeomFromText('POINT(13.114289 40.660615)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (567, 'Tirith Nindir', 'castle', 60, 'Gondor', 'An ancient Gondorian fortress built to protect and guard the approaches to the Dagorlad plain.', '9359778ea1b205b6557d2baf08c3ab0a', ST_GeomFromText('POINT(17.905348 45.591355)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (568, 'Lond Angren', 'city', 2300, 'Gondor', 'Lond Angren (S. Iron Port) began as a small Númenórean outpost of the Second Age and grew into a city and lordship controlling western Enedwaith near the mouth of the River Angren.', '93b9a677e74f4de70c374ef9b4d1f3d5', ST_GeomFromText('POINT(0.26102 45.144004)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (569, 'Dunlostir', 'town', 880, '90% Gondorian, 10% Dunman', 'Dunlostir is the centre of the cereal trade for central Calenardhon, with a market recorded since T.A. 808. Grain from the surrounding plains is gathered and stored here before being shipped east or south. The town''s granaries are its most prominent buildings — large stone structures that dwarf the modest houses around them. On market days the roads leading in are busy with carts and droves.', '9419384092d93b36f57a999d75f061bd', ST_GeomFromText('POINT(8.671436 46.206903)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (570, 'Tir Lawen', 'city', 600, '', 'Tir Lawen is a Noldorin Elvish city in the northern wilds, its tall spires visible from the surrounding hills as a point of light in an otherwise dark landscape. Founded in the early Third Age as an Elvish refuge, it is one of the few places of Noldorin habitation outside Lindon and Imladris. The city''s stonework is of exceptional quality; its halls are bright and its people reserved toward mortal strangers.', '96e3c8c5ca8e87d9f19586a2defc791a', ST_GeomFromText('POINT(-9.050462 51.986118)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (571, 'Onodrith', 'town', 1100, '95% Gondorian, 5% Dunnish', 'Onodrith grew around a ferry crossing of the Entwash in the tenth century of the Third Age, receiving a royal charter in T.A. 1240. It is a small market town and local administrative centre, handling most of the river traffic moving between Gondor''s northern and western provinces. Stone warehouses and timber wharves line the riverside; the ferryman''s charges are posted on a board at the landing.', '97426ecfc7ddec460434e0391aa40aee', ST_GeomFromText('POINT(11.433006 45.72867)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (572, 'Cor Angaladh', 'point of interest', 0, 'Silvan Elves', 'A ritual burial ground, now long disused. Once one of the most sacred sites of the Northmen, this place is now shadowed by the darkness of Mirkwood. Men of the north avoid it, believing it to be cursed.', '97e0564175cce6367da1abe875f4d424', ST_GeomFromText('POINT(19.715491 50.24128)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, external_id, geom) VALUES (573, 'Osgar', 'manor', 40, '', '98297a9393f615d3791c0ba38ac4bd4f', ST_GeomFromText('POINT(2.03246 42.157703)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (574, 'Dale', 'town', 570, '100% Northman', 'Dale is a handsome town of Urban Northmen set in a sheltered valley beneath the Lonely Mountain, seat of the Thyn and a manufacturing centre for the rural Northmen of the region. Its stone houses and workshops are famous for their fine toys and clockwork mechanisms; market-day brings traders from as far as Esgaroth and beyond. The mountain behind the town gives it a dramatic backdrop and a sense of permanence.', '9d8352b354ce40ca566050ea40fbc8c1', ST_GeomFromText('POINT(21.273306 53.880945)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (576, 'Rhosgobel', 'point of interest', 1, '100% Ista', 'Built by Radagast around T.A. 1100.. A place of healing and herb-lore; a refuge from Mirkwood; an observation post on Dol Guldur.. Rhosgobel is a simple place formed out of the boughs of a great furry oak tree.', '9eb4aada9066b6970cc3fa4b0713f534', ST_GeomFromText('POINT(15.953922 50.443346)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (577, 'Lond Galen', 'city', 5000, 'Gondor', 'The capital of Anfalas and its largest town, set near the mouth of the Celgalen where the river meets the Bay of Belfalas. About 5,000 inhabitants work as merchants, artisans, sailors and officials; most also tend plots outside the town for their daily bread. The town''s major building is the governor''s small manor; a few noble townhouses stand taller than the usual one- or two-storey stone buildings. A fifteen-foot wall (rebuilt in T.A. 1652 after Corsair raids became endemic) encloses the settled area, and a small fort guards the southern approach.', '9fa4fdeaf24042021af167466a61eb0e', ST_GeomFromText('POINT(4.722165 41.290999)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (578, 'Esgaroth', 'town', 910, '90% Northman, 10% Mixed Mannish', 'Esgaroth — the Lake-town — is built on great timber platforms above the Long Lake, connected to land by a single bridge. Founded as a seasonal trading station in the early Third Age, it has grown into the chief market of northern Rhovanion, where goods from Dale, Erebor, the Woodland Realm and the wide plains are exchanged. The platforms creak pleasantly underfoot; smoke from cook-fires drifts across the water; the Master''s Hall rises in the centre of the floating town, its banner visible from the lakeshore.', 'a309e72a5df0d83e90644ac100da32ae', ST_GeomFromText('POINT(21.777269 53.02214)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (579, 'Porosir', 'manor', 34, 'Gondor', 'A Gondorian castle and lordly manor in southwestern Ithilien, on the northern banks of the Poros. It is the western frontier seat of House Faron, whose domain guards this stretch of the borderlands. The castle is a working military manor of dressed stone, its courtyard always busy with horses and men moving on the Poros road.', 'a5bb5615f0cc150c33a7ad66fcfbbc3f', ST_GeomFromText('POINT(15.440753 40.605991)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (581, 'Tumnogoth Iaur', 'dwarven mine', 112, 'Dwarves', 'The Dwarves of Tumnogath were poor and secretive. Many of their young had emigrated to the distant Iron Hills, and the community stagnated over a few generations. The remaining Dwarven population consisted largely of treasure-seekers and travelling tinkers.', 'a89aa4a2e390d2650f651118a49c1f0c', ST_GeomFromText('POINT(-6.372691 49.954729)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (582, 'Carrock', 'point of interest', 'Beornings', 'Carrock was a great rocky islet in the Anduin, between Iach Iaur and Maethelburg, held in deep spiritual reverence by the Beornings who dwelt nearby. The Anduin was shallow here, allowing a ford near the Carrock, though the swift current made the crossing genuinely dangerous.', 'a93d0de04ea8b6508387274bbf869d77', ST_GeomFromText('POINT(15.064321 52.083825)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, external_id, geom) VALUES (583, 'Druabad', 'village', 206, '', 'a96509f98e363e3b03873960397c0cf8', ST_GeomFromText('POINT(5.446174 42.937788)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (584, 'Osgiliath', 'city', 2500, '90% Gondorian, 10% Mixed Mannish', 'Osgiliath was the founding capital of Gondor, built by Elendil''s sons on both banks of the Anduin at its widest point. Its great dome once housed a palantír; the Bridge of Osgiliath spanned the river in a single graceful arch. The city has suffered enormously — a great part was burned during the Kin-strife and the palantír was lost in the river — and by the mid-Third Age much of it stands abandoned or in ruins. The inhabited quarters on the western bank retain a ghost of former grandeur.', 'a999feb997c5cbac53d53ceb760be098', ST_GeomFromText('POINT(17.969459 43.351871)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (585, 'Tuckborough', 'town', 320, '', 'Tuckborough was the ancestral seat of the Took family, located in the Green Hill Country of Westfarthing. The surrounding area included the market center of Whitwell, the woodcraft village of Tuckburrow, and Dolwich, which supplied timber and granite to the southern Farthings.', 'b07dfd88fff335d40f4a6ff02e121d97', ST_GeomFromText('POINT(-1.324173 51.341565)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (586, 'Dol Caranthan', 'town', 320, '', 'A town of Anórien on the west bank of the Anduin, north of Cair Andros, seat of the local noble family of House Caranthôn. Its stone houses face the great river, and the ferry landing here sees regular traffic of soldiers and merchants. The Caranthôn family''s hall is the largest building in the settlement.', 'b173ca30c3da9f732cc0d30c3dba9b2b', ST_GeomFromText('POINT(17.402856 44.594583)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (587, 'Nothva Rhaglaw', 'town', 840, '90% Hillman, 10% Dunnish', 'Nothva Rhaglaw is the only permanent Hillman town west of the Mitheithel — founded by Broggha of Rhudaur in T.A. 1639 as a trading centre and point of local justice. It is a rough, busy place by the standards of the region: a market where Hillmen, Dúnedain and various others conduct business under the rough authority of Broggha''s appointed men. The buildings are timber-and-daub longhouses; the market square is unpaved and muddy in rain.', 'b2d97d738b6c8e1360c928f1f3978a23', ST_GeomFromText('POINT(5.969026 52.908717)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (588, 'Cameth Brin', 'citadel', 630, '60% Hillman, 37% Dunman, 3% Other', 'Captured and enhanced by Dúnedain, T.A. 162.. A stable center of administration for Rhudaur; domination of local Hillman tribes.. Currently, Cameth Brin serves as the seat of the Hillman King Broggha.', 'b45533711c7989e35801d15ea96e34b8', ST_GeomFromText('POINT(7.46718 52.537733)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (589, 'Faemar', 'town', 850, '', 'Faemar was a village set midway along the long, narrow Taur Galen, at a ford crossing the river. The steep valley downstream made farming impossible; villagers subsisted on wild game, berries, herbs, nuts, and wood for charcoal.', 'b5e41a73df163d7a3bc0212280694b87', ST_GeomFromText('POINT(-2.750008 54.559393)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (590, 'Ambon Noirinyaron', 'ruins', '', 'Ambon Noirinyaron — once a grand Elvish mansion — is now little more than overgrown foundations and a few standing columns. The dressed stonework suggests a high Elvish craft; vines and moss cover what remains. The place has an air of melancholy stillness.', 'b721357fafe99eb73f5c980838e5ddf1', ST_GeomFromText('POINT(-2.111696 53.302321)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (591, 'Dol Amroth', 'city', 0, '90% Gondorian, 10% Mixed Mannish', 'Dol Amroth — named for King Amroth of Lórien who drowned offshore in T.A. 1981 — is the great coastal city and seat of the Prince of Dor-en-Ernil. Its white towers rise from a high cliff above the bay; the harbour below is one of Gondor''s finest, home to the warships and tall-masted trading vessels of the southern fleet. The city has an Elvish quality to its older quarters — graceful stonework and the lingering influence of the Elvish settlement that once stood here — while the newer docks ring with the noise of any busy port.', 'b74257edfb64f85fb7085dc04ae70782', ST_GeomFromText('POINT(9.045753 41.368408)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (592, 'Little Delving', 'village', 120, '50% Harfoot, 25% Stoor, 25% Fallohide', 'Settled during the migration of Hobbits to the Shire, T.A. 1601-1610.. Agricultural community.. Located on the White Downs, Little Delving has a greater preponderance of smials.', 'b8e5b03dddef89acb43eb6b4c7704af1', ST_GeomFromText('POINT(-2.512654 51.660837)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (593, 'Lond-in-Telerrim', 'town', 546, 'Noldor', 'A Falathrin Elvish haven on the western coast, home to a community of Telerin Elves who raise sheep and work the sea. In the nearby Taur-in-Telerrim (''Wood of the Teleri'') persistent rumours circulate of a small drake lurking in the deep forest — though no search has ever found its lair. The haven''s whitewashed stone buildings face the water; the smell of lanolin and salt is everywhere.', 'ba1d1a32cd234ff8a9fa85f54f447d3c', ST_GeomFromText('POINT(-6.863374 50.840027)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (595, 'Stock', 'village', 210, '55% Stoor, 20% Fallohide, 25% Harfoot', 'Stock sits in the fertile Baranduin valley, its well-tended fields producing some of the best mushrooms in the Shire — a fact the locals are quietly proud of. It is a comfortable Stoor-majority village of low stone-and-turf buildings near the river, settled in the early days of the Shire. Travellers on the road to the Bucklebury ferry pass through here, and the smell of fresh earth and mushroom beds is pleasant in damp weather.', 'bcd8fc2e535e21125dcf84c78e30cfe8', ST_GeomFromText('POINT(-0.149413 51.43143)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (596, 'Bar-en-Dinnen', 'point of interest', 432, 'Gondor', 'Bar-en-Dinnen (S. Dwelling on the Dinnen) was a fishing village and river-trading town in southern Ithilien, about sixty miles south of Minas Tirith, at the junction of the Tinnen and Anduin rivers. As the only significant settlement in Harithilien north of Hyarpende, it was an important hub for river commerce between Ithilien and Lebennin.', 'bf4f93c27a04a22a4cb95b6e9b2da0ce', ST_GeomFromText('POINT(17.723223 42.143878)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (597, 'Mirolos', 'city', 300, 'Noldor', 'Mirolos (S. Jewel-Dream; also Londalos) was a Noldor settlement founded by followers of the Sons of Fëanor in the first decade of the Second Age, the largest community in the Hûb Conath region. Founded by Maglor before his disappearance, it was burned during the Long Winter when a northern dragon entered the area.', 'c02aee9a0462b65512c662491f3b69f8', ST_GeomFromText('POINT(-9.56661 55.290304)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, external_id, geom) VALUES (598, 'Tir Lawen', 'city', 800, 'Noldor', 'c0c86553afc2adf9fb424a578f332bea', ST_GeomFromText('POINT(-11.063029 52.948017)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (599, 'Annon Baran', 'village', 300, '60% Eriadoran, 40% Cardolani (Dúnadan)', 'Settled around T.A. 1200.. Economic hub for western Cardolan; provides fish for region.. Despite its proximity to the Elven land of Harlindon, few of the Cardolani dare cross the river, fearing the spells of the Eldar.', 'c0da45757ceef624d48f9d947ae16305', ST_GeomFromText('POINT(-4.147863 48.98546)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (600, 'Forondir', 'ruins', '', 'Forondir has been a ruin for long enough that the locals no longer know its original name. Only broken walls and overgrown plazas remain of what must once have been a city of some importance.', 'c2392ab49a7d6e2b9754ceb14dfb2040', ST_GeomFromText('POINT(-3.382325 47.966594)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (601, 'Anhamar', 'point of interest', '', 'The highland above the Anghir Vale where Anghul fortress stands — bleak moorland and dark rock, swept by the winds that give Anghul its name. No settlement of note, only military outposts and the occasional patrol of the Witch-king''s men watching the No Man''s Land.', 'c2f3aca4298632ac748eaa0343c9c2b9', ST_GeomFromText('POINT(-8.95062 50.767262)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (603, 'Hobbiton', 'town', 504, 'Hobbits', 'Hobbiton easter egg was a prominent Hobbit village in the Westfarthing of the Shire, north of the Great East Road. It was home to Bag End on the Hill — the residence of Bilbo Baggins and later Frodo Baggins.', 'c4fc66c91d78dea4ab769322dae7aeda', ST_GeomFromText('POINT(-1.265933 51.58473)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (604, 'Pinnornost', 'fortress', 540, '', 'A border fortress of Anfalas guarding the path of the Len Lefnui at the mouth of the Nan-i-Feryth, named for its position on a pine-clad ridge. Pinnornost was built in T.A. 823 to hold the pass on the frontier with the Daen clans of Haerawreigion. A beacon tower communicates with a sister tower thirty miles east. By T.A. 2157 the garrison was judged too costly to maintain; the fortress was locked up and has slowly fallen into disrepair since.', 'c56b60ec340561754e3980f516df9cf7', ST_GeomFromText('POINT(4.501772 43.140756)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (605, 'Vinyathrad', 'city', 800, '', 'Edenathrad (''New Ford'') is a ford and village north of the ancient Sarn Athrad on the Gelion. It replaced the older ford for practical traffic between Forlindon and the eastern lands. The village is a small settlement of stone and timber houses near the riverbank; Amboron is its chieftain. Traders and travellers cross here regularly.', 'c63a0fa990a9481746f987be890a420a', ST_GeomFromText('POINT(-10.131963 53.290973)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, external_id, geom) VALUES (606, 'Caborlad', 'point of interest', '', 'c66de1535d5084394d382b401eb3ed69', ST_GeomFromText('POINT(8.681894 42.644397)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (607, 'Glanhir', 'fortified town', 1300, '85% Gondorian, 15% Dunnish', 'Received royal charter in T.A. 630, possibly constructed upon Second Age Elvish ruins.. A collecting point for local farmers; an economic center for west-central Gondor; a river port.. Situated at the confluence of the Morthond and Ringló Rivers, Glanhir is considered the Gateway to Anfalas.', 'c7058608fefce8f43ee84942255feb8b', ST_GeomFromText('POINT(9.614062 42.073163)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, external_id, geom) VALUES (608, 'Erynwaith', 'point of interest', '', 'c954bfcce69f4d05de5e64251168df37', ST_GeomFromText('POINT(-0.389766 45.155728)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (609, 'Amrelor', 'ruins', '', 'Amrelor is a ruin. Whatever purpose this settlement once served, it was abandoned long ago, and the dressed stone walls have been falling for generations. The site is avoided by locals, who consider it unlucky.', 'c978f08eddb9e7e5d44df0e1dd8ecf49', ST_GeomFromText('POINT(0.584601 47.809059)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (610, 'Dol Guldur', 'fortress', 250, '90% Orcish, 5% Troll, 5% Other', 'Dol Guldur — ''Hill of Sorcery'' — rises from the southern extremity of Mirkwood on the summit of Amon Lanc, an extinct cinder cone. Since around T.A. 1050 it has been occupied by a power called the Necromancer, who has filled the fortress with Orcs and Trolls and spread a shadow over the southern forest. The hill is wrapped in a permanent gloom; the trees around it are dead or twisted, and Mirkwood''s darkness is deepest in its shadow. No traveller ventures near willingly.', 'cba3c1d32999386b7650ada2d73f473c', ST_GeomFromText('POINT(15.813102 49.377965)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (612, 'Serelond', 'city', 1300, 'Gondor', 'A town of Anfalas on the Celgalen, with about 1,300 inhabitants in small industry, local trade and subsistence farming. Stone houses of one or two storeys line the streets; weekly market; annual fair. The town hall is the tallest building. A typical, orderly Gondorian provincial settlement.', 'd051379b25c86cfac253bd6b01cea140', ST_GeomFromText('POINT(4.794315 41.460161)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (613, 'Dol Gwaer', 'fortress', 400, '', 'A lordly manor of the Nan Celgalen in western Anfalas, seat of a minor Gondorian noble family. Its stone hall and outbuildings sit in a wooded valley; the surrounding estate grows grain and raises sheep. A small household of retainers and tenants keeps the manor in order.', 'd23f71bd5455ab5a52471ba0e0682dbf', ST_GeomFromText('POINT(4.947357 42.98755)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (616, 'Lond Thalos', 'town', 700, '', 'Lond Thalos (S. Port of Thalos) served as both a medical and herbal community and as a timber port supplying wood to the shipyards of the Grey Havens.', 'd7b271fbd725a19c00232d158a1e71c4', ST_GeomFromText('POINT(-7.539279 51.414853)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (617, 'Scary', 'village', 130, '40% Harfoot, 35% Stoor, 25% Fallohide', 'Scary is a Hobbit mining and quarrying village in the rugged Eastfarthing, supplying most of the tin and copper ore used throughout the Shire. Its stone houses are sturdier than average for Hobbit settlements — the miners prefer solid construction — and the surrounding hills are pocked with mine shafts and quarry faces. The village has a slightly tougher character than most of the Shire: fewer flowers and more mud-boots.', 'd91f5d2806938b5d5e0342181bfff661', ST_GeomFromText('POINT(-0.386569 51.76395)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (618, 'Hornburg', 'fortress', 1600, '100% Gondorian', 'Built soon after the War of the Last Alliance at the end of the Second Age.. Quarters for a large portion of Gondor''s army in Calenardhon; administration and protection of the lands from the Isen Fords to Calmirië.. ''Hornburg'' is a Westron name; most Gondorians refer to the citadel as Ostiras.', 'db7308c49e9f0be82050b9f695ba8651', ST_GeomFromText('POINT(7.587706 45.859374)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (619, 'Hwalord', 'town', 520, 'Gondor', 'A town in the region, its stone houses and wharves serving the commerce of the surrounding area. Details of its exact character depend on the local economy and lord.', 'e11fba538e02b2f688cb4b67ef534ff3', ST_GeomFromText('POINT(-0.466877 44.654769)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (620, 'Elostirion', 'tower', 52, '33% Dúnadan, 66% Eriadoran', 'Built by Gil-galad as a gift to Elendil.. Home to one of the Palantíri.. Elostirion is the tallest and westernmost of the three White Towers in the Emyn Beraid.', 'e2bf97d453fbf8464e97036d01bec4d4', ST_GeomFromText('POINT(-5.219364 51.638056)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (621, 'Shedûn', 'castle', 940, '100% Angmarean (Mixed Mannish)', 'Shedûn is a Witch-king fortress overlooking the broad plains below Angmar, used for regional administration and as a mustering point for the Orc forces trained on the plain below. Its stone walls are of Angmarim construction — heavy and dark — and the view from the battlements encompasses a vast training ground where Orc companies drill with a grim efficiency.', 'e32e3dba06c560584d99f5162a2c4258', ST_GeomFromText('POINT(6.787443 54.830155)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, external_id, geom) VALUES (623, 'Bar Olchaldor', 'town', 348, '', 'e489b8b32e368a5305d8aa2099c2b4a3', ST_GeomFromText('POINT(15.996778 41.930038)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (624, 'Tharagdonrost', 'city', 800, 'Gondor', 'A city in the region whose size and character make it a significant centre of population and trade.', 'e5c97706503934aef315312d333b8692', ST_GeomFromText('POINT(-0.338978 40.06648)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (625, 'Moria', 'dwarven mine', 60000, '100% Naugrim', 'Moria — Khazad-dûm to the Dwarves — is the greatest Dwarven city ever built, delved beneath three peaks of the central Misty Mountains. In its heyday it housed tens of thousands; even now, with its population much reduced, the inhabited halls are vast and busy with the sound of hammers and the smell of forges. Travellers who have passed through its western gate describe colonnaded halls of astonishing size, veins of mithril visible in the rock face, and a beauty that is severe and magnificent at once.', 'e743898b5429b1759f42f3eeedf353a1', ST_GeomFromText('POINT(9.173216 49.128243)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (626, 'Eruimar', 'village', 98, '', 'Eruimar (S. Lonely Home) sat at the foot of the Ramluin (S. Blue Wall), below the easternmost point where the Ered Luin foothills gave way to rocky cliffs. Despite its remote setting, distance rather than forest or enchantment created its isolation. The village held no more than thirty-five households; founded by the Dúnedain, most of its roughly 150 residents were River-men or Northmen by the mid-Third Age.', 'e835ee53e05d2cfc5578bedc86581b87', ST_GeomFromText('POINT(-5.002044 53.408169)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (627, 'Halifirien', 'watchtower', 100, '100% Gondorian', 'Current tower completed in T.A. 529.. A link in Gondor''s chain of communications in Anórien.. Halifirien rests on the border of Anórien and Calenardhon.', 'e901438cd57190a3a650728131f750ba', ST_GeomFromText('POINT(13.655401 44.526185)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (628, 'Derwath', 'village', 250, '20% Gondorian, 80% Dunman', 'Settled by Gondorian pioneers around T.A. 609.. An agricultural community; serves administrative roles in the sparsely populated Westmarch.. The village serves as headquarters to a detachment of rangers.', 'eaf84f527feadbff51bfee980db3f493', ST_GeomFromText('POINT(6.088231 45.273966)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, external_id, geom) VALUES (629, 'Ostiras', 'town', 400, '', 'ec4f1479d90b8b2a23c1a63546f45010', ST_GeomFromText('POINT(1.248646 45.852942)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (630, 'Annon Wain', 'city', 2500, '', 'Annon Wain, in the upper Lefnui valley, was a local market center. To the north lay extensive mines whose ore was shipped downriver to Annúlond, while nearby firs from the Ered Nimrais supplied Gondor''s naval yards. The town itself was modest — merchant houses, simple dwellings, and riverside warehouses — with a population of roughly 2,500.', 'ed0fd50f861c8ccd1f7b1374b6c56a6f', ST_GeomFromText('POINT(2.668339 42.90054)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (631, 'Thoronbar', 'ruins', '', 'Thoronbar was a village that did not survive the troubles of the middle Third Age. Its ruins are modest: a handful of stone foundations and a broken well, half-buried in turf on the edge of an old track.', 'efc7cfee6d7f026f9b104f1dc82c5aa9', ST_GeomFromText('POINT(-2.408808 53.576487)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (632, 'Cerin Balgrist', 'ruins', '', 'Cerin Balgrist was once a city of consequence, but it has been a ruin for generations. The traveller finds only weathered stone, collapsed gateways and empty squares where a market presumably once met.', 'f0d0e1a0ee8699729e955990523bc22c', ST_GeomFromText('POINT(-0.685963 54.322353)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (633, 'Cum Arelaid', 'ruins', 'Gondor', 'Ruins. An ancient burial complex of pre-Númenórean tumuli and stone-lined graves, sacred to the early peoples of the region.', 'f2e70b1b048daf0397847538939dace3', ST_GeomFromText('POINT(4.688348 44.257728)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (634, 'Dunmardo', 'town', 111, '', 'A small Gondorian town or large village in central Anórien, seat of the county and ancestral holding of the noble family of the same name. Its Sindarin name means ''West-settlement''. Stone houses, a manor and a small market characterise this orderly provincial settlement.', 'f535f1f9c5a9cc4092a0e881020a584b', ST_GeomFromText('POINT(16.458038 44.238871)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (635, 'Min-rimmon', 'watchtower', 75, '100% Gondorian', 'Current tower completed in T.A. 516.. A link in Gondor''s northern communications network.. The fifth beacon in the series was built on a mountain named Rimmon.', 'f653065afba6a3d653b812c1d745ebdb', ST_GeomFromText('POINT(14.972117 44.364623)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (636, 'Ethraid Engrin', 'point of interest', '', 'The Fords of Isen were the main crossing point for those traversing the Gap of Rohan, with no bridge spanning the powerful river. The Rohirrim patrolled the area as their primary western gateway; Dunlending hillmen often seized the fords and demanded tolls. Three rows of broad flat stones crossed the waters, with graded horse-fords between them.', 'faa489819ad48c1b1b1bb97ec8a4989b', ST_GeomFromText('POINT(7.493416 46.358231)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, external_id, geom) VALUES (637, 'Annodrun', 'ruins', 'Gondor', 'Annodrun was a city that did not survive the troubles of its age. Its ruins are extensive — collapsed walls, empty market squares and the stumps of old columns — but they are uninhabited and slowly disappearing under vegetation.', 'fb3ba2c5b31fd725ba4a69888a9480a0', ST_GeomFromText('POINT(1.785819 40.782363)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (638, 'Melburg', 'city', 1200, 'Northmen', 'Maethelburg (Meeting Fort) controlled virtually all trade through the upper Anduin valley and produced large quantities of tin from the lower Hithaeglir mines. Travelers heading west stocked up before crossing the Misty Mountains; those arriving from the east rested here. Built on an artificial mound behind a massive timber palisade, it harbored an unusually high number of spies due to its proximity to Angmar and the Orc-holds of Gundabad.', 'fd53c3e33a8c151837e9703ed90efc50', ST_GeomFromText('POINT(14.879038 52.906108)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (639, 'Iach Sarn', 'town', 220, '', 'Iach Sarn clustered about the base of a limestone hill, surrounded by small farms and hardwood groves. On the south bank, just downstream of the main road, lay the ruins of an older village of earth-and-stone construction. Weathered steps led down a rubble embankment to the riverside docks, lined with unpainted ferries and fishing boats.', 'fe3eeab238fd22a00d7618e979b0b310', ST_GeomFromText('POINT(-0.586982 50.009316)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, external_id, geom) VALUES (640, 'Bar en Dagorath', 'fortress', 80, '', 'ff2232851941e9cd4928cae2dc656891', ST_GeomFromText('POINT(2.105156 55.136498)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (641, 'Carn Dûm', 'fortified town', 5000, '60% Angmarean, 40% Orcish', 'Carn Dûm sits at the northwestern tip of the Misty Mountains, the last great fortress of the Witch-king and the capital of Angmar. Its caverns and tunnels were originally delved by Dwarves; the Witch-king enlarged and fortified them enormously after T.A. 1300. Almost nothing is known of the interior — few of the Free Peoples who have approached it have returned. The mountain above it is perpetually dark with snow-cloud, and the road leading to the gate is guarded at every turn.', 'a90a43d1458f4bc23cafcc17a8951ca4', ST_GeomFromText('POINT(5.713727520310158 56.040605368313436)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, external_id, geom) VALUES (642, 'Estomar', 'city', 324, 'Noldor', '5324545435545', ST_GeomFromText('POINT(-9.641471810978715 56.4614552500048)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (873, 'Brandy Hall', 'town', 'The traditional Great Smial of the patriarch of the Brandybuck clan and Master of Buckland. Built by Gorhendad Oldbuck around T.A. 2340 after founding Buckland, and greatly expanded over generations by his descendants — most notably Gormadoc ''Deepdelver'' Brandybuck c. T.A. 2800. This vast complex of tunnels and rooms is delved entirely into Buck Hill, with three large front-doors, many side-doors, and about a hundred windows. The ancestral home of the Brandybuck family; childhood home of Frodo Baggins. Inhabitants: 100% Stoor Hobbit.', 'c65fe8733f68ed0acf9d8657916491a7', ST_GeomFromText('POINT(-0.109475780513291 51.337187824592014)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (874, 'Newbury', 'town', 'A Buckland village, the only one set inland from the Brandywine. Before the completion of the High Hay, it occupied a fortified hilltop; the old tower has since been taken down. Today Newbury is a comfortable Hobbit settlement centred on Gorbuck Hall, delved into the hillside. The Hall keeps some almost-forgotten rooms as a Mathom House for relics of the wars against the Old Forest — old weapons, flame-arrows, and mouldy tomes. One or two Gorbucks in every generation study these things quietly, just in case.', '26423f24ed502b4bcd43f6bb8c4fbfe5', ST_GeomFromText('POINT(0.110795383046252 51.445392173867724)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (875, 'Bankling', 'town', 'Known locally as ''Bankling'' and later Whitfurrows, this good-sized Hobbit town sits squarely on the Great East Road in the midst of the best farmland of the Eastfarthing. Heavy wagons cross the Scary Pike at Budge Ford to the north, while a fine wooden bridge takes lighter traffic to Waterbury across the river. The town is known for its corn and flax fields and for the Blushing Ivy Tavern, meeting place of the Brow, Pen and Scroll Society — a bookish Hobbit club with a taste for Elvish lore that gives them a reputation for peculiarity among their neighbours.', '9123f084119aaf39753e9c22647f86e5', ST_GeomFromText('POINT(-0.281059651949529 51.57042208785768)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (876, 'Rushy', 'town', 'A riverside village in the Marish, where Rivermen and Stoor Hobbits live uneasily side by side. Euric Thuigildsun, the ancient white-haired patriarch of the local Riverman clans, eyes the new Stoor immigrants with cautious acceptance, hoping for commercial advantage. His rival Thuidimer of nearby Flynettle outmanoeuvres him regularly. Rumours of strange reptilian creatures seen on the marshland trails between Rushy and Flynettle add an uneasy note to an already tense village.', '97a83eaeedfbbb530bd4d4e021dd40c6', ST_GeomFromText('POINT(-0.3063138415665 51.24559960169455)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (877, 'Standelf', 'town', 'A small hamlet in southern Buckland, close to the High Hay and the Old Forest. Originally built to house miners working the local delving (''Stangedelf''), it grew into a small Hobbit village of stockbreeders. Most inhabitants are a poorer branch of the Brandybuck clan; the Goldworthies, Gorbucks, Headstrongs and Puddyfoots are other families here. The Old Forest looms to the south.', 'ecb5d5c8e62a59b813f34f92c8a1a7b9', ST_GeomFromText('POINT(-0.212581431541162 51.23679752011409)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (878, 'Haysend', 'town', 'A small Hobbit village at the southern end of Buckland, where the High Hay meets the Brandywine''s marshy mouth. The Withywindle swamp begins just beyond; Bucklanders from Haysend, Breredon and Grindwall fish these swamps and can be hired to take travellers downriver. Buckland''s shirriffs gather here twice a week to patrol and maintain the High Hay. The settlement is small but watchful, its people accustomed to the odd noises that come from the Old Forest side of the river.', 'f2740ff0ee4e682dd42f14fe7788b420', ST_GeomFromText('POINT(-0.201530827107401 51.15005956562732)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (879, 'Flynettle', 'town', 'Flynettle in the mid-Third Age is a rough river-landing and fishing camp on the Anduin — nothing more than a landing stage and a handful of sheds used by riverboat crews. The old Deep Hallow House is a crumbling ruin on the bank, avoided by locals.', '660d56b4a55bdf2e6d25b67a7ab178bd', ST_GeomFromText('POINT(-0.327403633822201 51.14133364945998)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (880, 'Willowbottom', 'town', 'A village in the Eastfarthing of the Shire, near the Baranduin and the Overbourne Marshes. A secret ford used by Elven Wandering Companies lies near here. The village sits on the Elfwood stream close to where the Thistle Brook flows into the Shirebourn — a marshy, willow-edged landscape of low Hobbit cottages and kitchen gardens.', '9a6e4f2203ee98ab95b6fcba6d34c6ab', ST_GeomFromText('POINT(-0.603914243396946 51.06923781163512)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (881, 'Pincup', 'town', 'A quiet Hobbit woodland village in the Southfarthing. The founding Pendle family are long gone; the Goodbodys are now the most prominent residents, though the Tooks are the main landowners. The village has a reputation for being an unusually secluded and woodsy sort of place, and Sîrrandrai Elvish artefacts occasionally turn up in local mathom collections.', 'fcde32bbf605a675b192c68054fc08e4', ST_GeomFromText('POINT(-1.116981814409183 51.22908454863549)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (882, 'Tookbank', 'town', 'A Hobbit market town in Tookland, associated with the Took family. Its market brings farmers and craftsmen from across the surrounding area on market days.', '50e6d0af4c8566c0039a4e37af8e3492', ST_GeomFromText('POINT(-1.514257594710213 51.334302166134286)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (883, 'Whitwell', 'town', 'A small Hobbit village near Tuckborough in the Shire, known for its good wells and its quiet lanes. Taken over by the Tooks around T.A. 1620 and briefly notorious when residents started charging road tolls and detained a King''s Messenger — a stiff fine settled the matter. Paladin Took owns farmland here. The village is small and amiable, though Tooks from Whitwell are reportedly not always welcome at certain fords since the toll incident.', 'b3a13760464ed8b72113797943230c76', ST_GeomFromText('POINT(-1.633772169279555 51.336819792142244)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (884, 'Wood Junction', 'town', 'A Shire village in the Westfarthing, 15 miles west of Bywater on the Great East Road, where the Sarn Ford road meets the main road. Originally called Wood Junction in Arnorian times, later shortened to Waymoot by Hobbits. A natural stopping point: a comfortable inn and a few houses cluster at the crossroads, busy with traffic between Bywater and Bree.', '50eb2bd6e21331eabe40b3822d3f357d', ST_GeomFromText('POINT(-1.548635046923086 51.465401238033515)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (885, 'Bywater', 'town', 'Settled as a crossroads village by Men of Arthedain in the early Third Age; later resettled during Hobbit migrations to the Shire, T.A. 1601-1610. An agricultural market village at the crossroads of the Great East Road, frequented by traders and travellers passing between Hobbiton and the East Farthing. Bywater lies just north of the Great East Road on the banks of a small pool, and is known for the Green Dragon Inn. Inhabitants (c. T.A. 1640): 50% Harfoot, 40% Fallohide, 10% Stoor; population approx. 360.', '1e2601daa09bf65f5c8b09d63001711a', ST_GeomFromText('POINT(-1.13209469050118 51.5659580479751)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (886, 'Overhill', 'town', 'A new Hobbit village north of Screaming Hill, settled by the Fallohide Barleycorn clan and the Harfoot Beechkins, both of whom came to the Shire after being persecuted by brigands. The two clans share a suspicion of Big Folk that occasionally turns hostile; other Hobbits are uneasy about the disappearances of Men who venture into the angle between Baining Stream and Screaming Hill. In later, more peaceful times, Overhill becomes a comfortable farming community; the Bagginses own much of the surrounding land.', '5d85a4bd0836ee72c9a7e8f2c3a114a8', ST_GeomFromText('POINT(-1.278787595579377 51.66757438362121)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (887, 'Waterbury', 'town', 'A Hobbit village on the north bank of the Fairwater opposite Bankling, providing access to the Great East Road for miners of the Hills of Scary. It has outgrown its twin settlement as Hobbit migration increased. Later it evolves into the village of Budgeford.', 'fb5c6b2990b5c1f9dd1f7a9cfc696a21', ST_GeomFromText('POINT(-0.268820877556365 51.62395214709121)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (888, 'Woodhall', 'town', 'A Hobbit village in the Eastfarthing on the northern eaves of the Woody End, founded in T.A. 1612 by Harfoots of the Staghorn and Huckle clans on the site of an old Eriadorian village. The earlier settlement was destroyed in T.A. 1409 when Orc wolf-riders slaughtered its inhabitants. The new Hobbit village sits where those same apple orchards still bear fruit and mushrooms grow on shaded terraces. A glade of the Elven Wandering Companies lies nearby; Elves are sometimes seen passing through at dusk.', '2e86b2f41901c239c3d12ef31492d5c7', ST_GeomFromText('POINT(-0.512120491248156 51.3231202577711)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (889, 'Longbottom', 'town', 'A Hobbit village in the Southfarthing, historically significant as the first place in the Shire where pipe-weed was cultivated. Around S.R. 1070 (T.A. 2670), Tobold Hornblower of Longbottom brought the pipe-weed plant from Bree and began growing it in his gardens, giving rise to the famous ''Longbottom Leaf'' strain. The village lies in a gentle valley of the Southfarthing and its fields are given over largely to pipe-weed cultivation, the primary industry of the region.', '6b4893099af8f5f03ba467cbc6af8752', ST_GeomFromText('POINT(-1.35611683385028 50.776765587848494)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (890, 'Brocken Borings', 'town', 'A Hobbit village on the western side of the Hills of Scary, centred on copper and tin mines, some dating to Dwarven miners of the Second Age. Hobbits here — chiefly the Bolger clan — use the old mine shafts as smials, ignoring old Riverman stories that the borings are haunted. There have been inexplicable noises, felt presences and glimpsed faces in the dark passages; in a small shed in the park, ''Neblin-nuggets'' — copper nodules roughly shaped like sleeping Dwarves — are displayed as curiosities. A remote and self-contained Hobbit community.', '59909f0afcb249dc1d193cbd1a0e997d', ST_GeomFromText('POINT(-0.60625755364758 51.81376537263118)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (891, 'Dwaling Bank', 'town', 'Originally ''Dwola''s Bank'', a streamside village with access to the Brandywine by a stream through a swamp — a relatively unguarded entry from Arthedain. In earlier times Rivermen here baked charcoal and kept quiet, aware of an Elvish community a few miles to the northwest. After Arthedain''s fall, a quiet resolution left the west bank of the Brandywine to the Shire-folk, and the village became a peaceful Hobbit settlement called Dwaling — a stopover for mild-mannered northlanders and a base for river traffic to Rood.', 'be7ec50630795002f7dfbe5b68b303b0', ST_GeomFromText('POINT(-0.165902829267255 51.915630700513084)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (892, 'Combe', 'village', 200, '60% Bree-man, 40% Stoor Hobbit', 'Settled by farmers from Bree in T.A. 1415.. An economic center for those unwilling to trek to Bree; agriculture.. Combe is the most isolated of Bree-land''s villages.', '4a9997e9ddf3c8e1ec038768b7a20760', ST_GeomFromText('POINT(1.40430264139591 51.5959391023737)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (893, 'ruins', 'ruins', '31ff135719880201f7f9afee7e554f57', ST_GeomFromText('POINT(1.358170285176331 51.09140864638483)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (894, 'ruins', 'ruins', '4d7fb89cc5ed5d76e4d0397b3565f561', ST_GeomFromText('POINT(1.315079903477513 50.733689290698386)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (895, 'Nobottle', 'town', 'Nobottle was a small logging village just off the Fairwater road between Little Delving and Bywater. Its Cutters'' Guild was known throughout the Westfarthing.', '0f7c547ffd39849d99de94f2d8d06762', ST_GeomFromText('POINT(-2.077856391045377 51.71224362521898)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (896, 'Long Cleeve', 'town', 'The Shire community with the best access to the Hills of Evendim and the Utter North. Long Cleeve is a lively market town that trades in furs, ivory, antler and deer-hide brought in by Rangers, hill-folk and trappers from beyond the bounds. The Northwatch shirriffs — who carry bows and spears rather than the usual staves — are headquartered here. A coppice nearby shelters a monument to Bandobras Took, hero of the Battle of Greenfields, who is also the town''s most famous former resident.', '73762dd51334e0a11185fa1eab7054d8', ST_GeomFromText('POINT(-2.326247277612521 52.2294150659081)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (897, 'Greenfields', 'town', 'A market centre for the northern Shire, Greenfields also serves as a meeting place for traders from the Twilight Hills and beyond the bounds. When available, trout from Lake Evendim and pike from the upper Brandywine are sold here; fine woolens woven from North Moors sheep are a speciality, made in sizes for Big Folk as well as Hobbits. The town''s Chief Shirriff is tougher than most, dealing with Rangers, Rivermen and hill-trappers who drift in from the north. A coppice east of town shelters a monument to Bandobras Took''s victory over the Goblins of Mount Gram.', 'f08cda88f938c90378990ce27b111a25', ST_GeomFromText('POINT(-1.461565795128782 52.41560967590633)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (898, 'town', 'town', 'eba1cbbf1ab59addd3a8766ae556fe3f', ST_GeomFromText('POINT(1.369152987636412 52.957857622794236)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (899, 'Aran Nov', 'town', '35ee86da8a5ce2c05fb8ba1911cb8bee', ST_GeomFromText('POINT(1.404851532016717 52.72494897202548)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (900, 'Dol Occum', 'town', 'A hill-tower on the Men Formen in southern Arthedain, within the village of Occum. The tower is a Dúnedain watch-post commanding the road; the surrounding village of timber and stone houses provides the garrison with supplies. The name derives from an older Westron name meaning ''ox-valley'', and cattle are still the main wealth of the area.', '78d344dbf17b5dc48c3a7f6a9443bdac', ST_GeomFromText('POINT(1.349193122322411 52.255960176185184)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (901, 'ruins', 'ruins', '1a4938c506e6ed19ae0e66731c821538', ST_GeomFromText('POINT(5.048683001237521 51.559819248497654)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (902, 'ruins', 'ruins', 'f6c5dd2f7048657297f73329436d929c', ST_GeomFromText('POINT(6.643338425130473 51.63788293276029)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (903, 'Morva Tarth', 'town', 'The town of Móin Dúldachd (''Marsh of Mist'') shares its name with the surrounding peat bogs of northern Rhudaur. A single track threads the swamp; those who leave it risk hidden bogs that are virtually bottomless. The town itself is the centre of what economic life exists in the Ettendales, and its chief fortification — the Kaldabaurg — was once the citadel of Northman mercenaries who served the Dúnedain. A grim, isolated place.', 'c5e33dceafd0ba1254eb7021cfacf7e3', ST_GeomFromText('POINT(7.506295563454326 53.24595472167379)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (904, 'ruins', 'ruins', 'eafe43efbadb6b849703a7bf6c90cac2', ST_GeomFromText('POINT(10.787766882323357 52.84679801592142)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (905, 'Ahus', 'town', 'A rough village of the Fell-men in Angmar, near the fortress of Angsûl. Its squat stone-and-timber huts sit in the shadow of the Witch-kingdom''s northern hills, home to a tribe loyal to the Witch-king. The settlement smells of smoke and animal fat; life here is harsh and martial, and strangers are rarely welcome.', '2133416d1765a745d13af9eb9e352eab', ST_GeomFromText('POINT(6.028935284576269 55.620009748829524)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (906, 'Phaluran', 'town', 'A township of the Tulban district of Angmar, built in the mid-Third Age and home to about 3,500 at its peak. The settlement is a rough frontier place — dark timber houses in the shadow of the Angmar hills, its people bound by the Witch-king''s will. With the fall of Angmar, the town is eventually abandoned. By the late Third Age only ruins remain: dark and windswept, avoided by all.', '7e38a66a4f07efd9be8bc2c055503d9f', ST_GeomFromText('POINT(6.646131166678444 54.68454577015133)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (907, 'Tying Field', 'town', 'A Hobbit village in the Westfarthing, originally called Tying Field — home of the Gamwich, Gammidge and Roper families. The Gamwidge rope-walk is here, and the town''s trade in hemp rope is well known. A ford over the Flexen Stream gives access, though the surrounding Mistvale woods have an unsettling reputation. No inn at the ford.', '65b8a07c66167e4eed1339ee906cf68c', ST_GeomFromText('POINT(-2.751444142252875 51.932871796216546)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (908, 'town', 'town', 'f0c84a451ee0bf4cc8b1ca1922e4c9fa', ST_GeomFromText('POINT(-4.642183553926161 51.60355254875421)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (909, 'Grimsly Dale', 'town', 'A Harfoot farming village located in a bend of the Fairwater River,quiet place, famous for its flowers . Although few remembered it , there had once been a scenic trail in the area that was a popular sidetrip on the Woodland Tour. Reason for its popularity could be discerned in the dense concentration of berry bushes and flowering plants along the riverside paths . The village got its name , however, from the bones of men and horses that also turned up along the trail . A large party of Dúnedain were ambushed here during the Scourging of T.A . 1409 ', '89d373cfa1cc533ebcf224a90453e632', ST_GeomFromText('POINT(-1.802421935625882 51.74103996842529)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (910, 'Rendwalk and The Briary', 'town', 'Waymoot (originally Wood Junction) is a Shire village in the Westfarthing on the Great East Road, 15 miles west of Bywater, where the main road from Sarn Ford joins the Great East Road. A natural stopping point for travellers; a modest inn and some houses cluster at the crossroads. The name changed from the Arnorian ''Wood Junction'' to the Hobbit ''Waymoot'' over the centuries.', 'fe751621b3441d9f5270cb31b5a5bfcf', ST_GeomFromText('POINT(-2.152652789927937 50.89560176854078)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (911, 'Rond Morvin', 'manor', 'A secluded Arthadan manor in a river-valley west of the North Moors, close to the North Farthing of the Shire. Rond Morvin controls the ford where the Men Lindon crosses the Barluin Stream; it serves as a gathering point for local fairs and militia musters. The manor is a solid stone house with stables and barns, its household accustomed to hosting travellers and muster-parties.', '5187009655be70b5b86e5feac7225b8d', ST_GeomFromText('POINT(-3.127986781343948 52.49349526437371)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (912, 'Ron Hyarr', 'manor', '05390378a9b03062a446fd37d54c9ca8', ST_GeomFromText('POINT(-2.612400525867402 52.55343009105157)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (913, 'Telwaen', 'town', 'Once a large township of 5,000 in the Girithlin highlands of Minhiriath, called Thuilwaen (''Stained helmets''). By T.A. 1400 its population had collapsed and the town was abandoned. What remains today is a ruin amid the highland scrub, its stone walls tumbled and its lanes grown over. Locals do not linger.', 'a6b070324a54f2919a1bc9c252dce3ad', ST_GeomFromText('POINT(-2.39537737237395 47.492400213632045)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (914, 'Dinach', 'town', 'A hilltop town in Mintyrnath, two days'' walk northwest of Tharbad. It sits on a strategic spur overlooking the junction of the Sendiel and Andeithel rivers, where an old Arnorian stone bridge still spans the water. In the mid-Third Age, Dinach is a rough waystation: a small garrison holds the old tower, and the stone buildings along the Men Formen shelter travellers, smugglers and agents of various factions. The low-lying fields along the river flood every spring.', 'cea8573a514b0db3d859b68c978b1e84', ST_GeomFromText('POINT(2.324096862485927 49.28939841701387)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (915, 'Vindacil', 'town', '4e34009af319cecbf925dfa46c15b7dd', ST_GeomFromText('POINT(3.505297853911119 48.67361014645488)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (916, 'camp', 'camp', '2495321424967445cae76aeb20b99a60', ST_GeomFromText('POINT(3.889309068791732 55.066626992078554)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (917, 'camp', 'camp', '2ac8dc76496757050bb464e3af398436', ST_GeomFromText('POINT(3.250560054699432 55.315362532985816)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (918, 'ruins', 'ruins', '399bb37fd281fc1e85960706ebeefbaa', ST_GeomFromText('POINT(4.057661522118384 55.30127142846688)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (919, 'camp', 'camp', '5f9e46bf2ade43c17d485395a1d97a39', ST_GeomFromText('POINT(2.150079679645064 55.45880602341437)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (920, 'camp', 'camp', 'c34117ed3c2b520e8081556298cf682e', ST_GeomFromText('POINT(1.045885647532019 55.49949402634118)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (921, 'camp', 'camp', 'f8f3a8ca64fdbcce0f9246db55c5054e', ST_GeomFromText('POINT(-0.007555071445785 55.35760581470521)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (922, 'tower', 'tower', '1ce7431bbba82600bfb60c69a069a8fb', ST_GeomFromText('POINT(-1.47011700972108 54.17072869316659)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (923, 'tower', 'tower', '8c867aabed9c32244861511902041521', ST_GeomFromText('POINT(-1.960319741466333 54.45524626139686)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (924, 'tower', 'tower', '618e820bb562c3063b332ba774b850a3', ST_GeomFromText('POINT(-0.910592679547205 54.384661674173415)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (925, 'manor', 'manor', 'ba9cd8f31b3c1f257719b5ca73a44cd2', ST_GeomFromText('POINT(-3.027996145835728 54.23734035805953)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (926, 'Adrahil''s Shield', 'inn', 'f0576b8c8700095bb8fe1d92ab359227', ST_GeomFromText('POINT(-2.357062103901569 54.380336219560036)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (927, 'Groddig Inn', 'inn', 'd2be09fcc585154c55f8702657057ce0', ST_GeomFromText('POINT(-1.091323989736111 54.25180694670706)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (928, 'manor', 'manor', '80c28af3905ca4e6aefcfe9fe6f009b0', ST_GeomFromText('POINT(-0.653112456812324 54.22865796974938)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (929, 'manor', 'manor', '0136ed6e661377ad91063cd8190d2a00', ST_GeomFromText('POINT(-2.116293337930732 53.869645519050046)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (930, 'Bauruin', 'ruins', 'Gobel Paurruin (''Village of the Firefist'') was once a thriving township on the Uialduin, about seventy miles northwest of Annúminas. At its height in the early Third Age it held some 3,600 inhabitants. By T.A. 1400 it was abandoned. What a traveller finds today is a ghost of moss-covered foundations and broken walls reclaimed by scrub and willow — locals call it a haunted place and do not linger after dark.', '9899ed13d73e0b58b624def471fd7567', ST_GeomFromText('POINT(-2.012310940287799 53.59577591554835)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (931, 'manor', 'manor', '1288814c3964d02f63905f2cf0d1287b', ST_GeomFromText('POINT(-1.990028997935742 53.40433269559471)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (932, 'Azaghâl''s Anvil', 'inn', '8c39448e7c69258c6c93117556c0be35', ST_GeomFromText('POINT(0.378046319813423 54.62042696646072)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (933, 'manor', 'manor', '047c7c4e70dd2290d17b4ec62d61f0aa', ST_GeomFromText('POINT(0.514213745298216 54.91180081036859)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (934, 'manor', 'manor', 'c2d9e184a06ef1cc5122e8b9e141fea8', ST_GeomFromText('POINT(-2.829934436039666 53.29645067997271)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (935, 'Rond Orro', 'manor', 'A manor in the region, its character and household determined by its local lord.', 'e482620a843795dc5e4be45e9e563745', ST_GeomFromText('POINT(-2.032736054110517 52.853218651896334)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (936, 'Ralt''s Corner', 'inn', '4cf4d38a9f94a2053ae3a643f12c47bc', ST_GeomFromText('POINT(-2.124339594891196 53.19422888013508)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (937, 'Brelmodoc''s Rest', 'inn', 'aa00d6a625187aecf117a5166629e60a', ST_GeomFromText('POINT(-3.21429794161265 53.07986681731324)', 4326));
