INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (944, 'cavern', 'cavern', '31532e86b402a9ad3ef234950575a3c0', ST_GeomFromText('POINT(-1.129862011886888 54.461699960817796)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (945, 'Falastir', 'manor', '70088012e3ad92af10e69c71a18ae8a5', ST_GeomFromText('POINT(-9.778746847887763 50.71664965907998)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (946, 'manor', 'manor', 'efc196ac2e8bbc51b7fdea41362368b0', ST_GeomFromText('POINT(-10.18837277054865 50.36215083990908)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (947, 'The Dend Haven', 'inn', 'a98c3eb0ff6ce332d7300bfbecf74419', ST_GeomFromText('POINT(-10.680795422258013 50.752504470191425)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (948, 'manor', 'manor', '7ade059f421bccab71f9b8f2725164fc', ST_GeomFromText('POINT(-10.44112068027558 50.92587377404722)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (949, 'manor', 'manor', '9089f70628b953b8299429a65b2db87a', ST_GeomFromText('POINT(-8.310194337922669 51.005462289207145)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (950, 'manor', 'manor', 'b769f36d70cf709d5901676bfd21ae13', ST_GeomFromText('POINT(-10.724372648073002 51.002720127355516)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (951, 'Lildamar', 'town', 'A town in the region whose character is shaped by local geography and trade routes.', '0afa0111fc8fe16dc74d33e526e09bac', ST_GeomFromText('POINT(-10.139348391506788 49.42880451498685)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (952, 'town', 'town', 'c0a7cd228052be946fde38f68925591c', ST_GeomFromText('POINT(-9.299397363922894 49.45926302421696)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (953, 'Linnuis', 'town', '0c1f8bf2005507bd37574af5151bd761', ST_GeomFromText('POINT(-3.035171153018341 47.25729219880642)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (954, 'Ilfin', 'town', 'Once a township of 3,100 on the coast of Cardolan, Dol Ilfin was abandoned by T.A. 1640 following the Great Plague and regional collapse. A traveller arriving here in the mid-Third Age finds only weather-beaten ruins on the coastal slope — empty windows in crumbling walls, and gulls nesting where people once lived.', '09aad3bdfae7f11ae5981f4d0583574e', ST_GeomFromText('POINT(-1.518683694656744 46.85650782519681)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (955, 'Chalnen', 'town', 'A village that served as Saerlann''s northernmost outpost along the Minsiril. In troubled times it is a rough place, known to mercenaries as ''Vice-town'': a refuge for camp-followers, spies, deserters and opportunists. The local chieftain Cyllin does business with whoever pays. Stone huts and muddy lanes; a few alehouses that never close.', '5c24b567891cc2dbe927c73df62b34df', ST_GeomFromText('POINT(-0.385675823467044 48.070219660060765)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (956, 'Carathel', 'town', '82b7f6c436a802ab742ad8e60f2d75c2', ST_GeomFromText('POINT(-2.542748501308971 48.877670933209046)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (957, 'Cor Wilishar', 'town', 'A Nandorin settlement built on a high crag above the Baranduin and the Nenglos. The village was abandoned in the years following the Great Plague and the collapse of Cardolan (c. T.A. 1700). By the mid-Third Age, travellers approaching the crag find only the stone footings of old platforms and the rusted remains of rope-ladders; the Nandor who once lived here are gone.', 'ca0aee863131ced156bc3e8967ad51bd', ST_GeomFromText('POINT(-2.272569701256043 49.48651796209594)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (958, 'Argond', 'castle', 60, '50% Dunman/Eriadoran, 40% Cardolani, 10% Dúnadan', 'Finished by the Prince of Dol Calantir in T.A. 887.. A stronghold and administrative center for rural lordship.. Though it appears formidable, the Argond was not designed with defense in mind. Its questionable defensive arrangement has yet to stand the test of a full siege.', '6ec7cdafef836d4596db02e9e426cf77', ST_GeomFromText('POINT(1.698405001134777 48.70254310541345)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (959, 'Undrond', 'town', 'Udûdhrond (''Deep-hidden vault'') was once a township of 4,300 on the west bank of the Gwathló, about eighty miles downriver from Tharbad. By the mid-Third Age its population had collapsed following the Great Plague and by T.A. 1970 the town was fully abandoned. What remains is a stretch of crumbling stone foundations along the riverbank, half-hidden by vegetation — a haunted silence where a busy market once stood.', '92de3edf6a912695d755593861823454', ST_GeomFromText('POINT(1.855283014068735 48.225771330158274)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (960, 'Helegnel', 'village', 'Once a free town of Cardolan, Gobel Helegnel was a settlement of some 4,100 people in the early Third Age, lying in the central lands of Dol Tinereb about 110 miles west of Tharbad. By T.A. 1400 its population had dwindled and the town was abandoned. What a traveller finds in the mid-Third Age is a landscape of crumbling stone walls and empty hearths, slowly disappearing under woodland regrowth.', '69b4ce32c5ecf2d3dae6baef4469264f', ST_GeomFromText('POINT(1.436941646244846 47.9638250125099)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (961, 'Erynwaith', 'town', 'd0d5165b778e4e7958b9b85ca7afe505', ST_GeomFromText('POINT(-0.549090420273252 44.93627356025649)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (962, 'Gwahilmoth', 'town', 'A township of Dol Caladir in Minhiriath, about sixty miles west of Tharbad in the central Baranduinean lowlands. In its prime (T.A. 250) it held some 5,000 souls. However by the mid-Third Age its population had dwindled sharply following the Great Plague and regional instability, and the settlement is largely abandoned by T.A. 1640. A traveller finds a melancholy landscape of empty stone foundations and overgrown lanes where grass pushes through the old cobbles.', '29a4b126976fdccab9c4ed7c88397f9f', ST_GeomFromText('POINT(1.241933560722772 48.61114857042575)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (963, 'Dol Ninden', 'town', 'Dol Nendin (''Hill of Silent Water'') is a settlement in Minhiriath that has changed hands in regional conflicts among the Lords Allied and the Cardolandrim. The town sits on a prominent hill above a quiet tributary, its stone walls bearing the scars of past assaults. In peaceful times it is a modest market centre for the surrounding farmland.', '3a69b6cc15d82b466745c6d8a3611f36', ST_GeomFromText('POINT(0.082779354044081 48.29032459528381)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (964, 'town', 'town', '0e1093ca53f16c458c0ecf13de85e251', ST_GeomFromText('POINT(-2.72032569650505 48.48710591824464)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (965, 'Dodind''s Tavern', 'inn', '41855b66d361dcb17f916166c7e57894', ST_GeomFromText('POINT(-7.332055541051707 49.765156129584796)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (966, 'The Zant Shield', 'inn', 'd620864097aa2c283e7cf6a951bf7782', ST_GeomFromText('POINT(-7.176333230867754 49.427246516371504)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (967, 'The Aglahad Blade', 'inn', '0f38276d8edc194d6c669c84167d8c9b', ST_GeomFromText('POINT(-7.189874301318533 49.62208646772963)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (968, 'manor', 'manor', '88cbb23a7d63cd8f11de2696f294fbc2', ST_GeomFromText('POINT(-6.566985060582721 49.68345360877144)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (969, 'Caras Denethora', 'village', '5ef05d4e0b3e2b097a90ccf712703c43', ST_GeomFromText('POINT(-6.420290130699287 49.433117691244256)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (970, 'Dremant Inn', 'inn', 'a6e7dbee08275ead0781039fe12755ba', ST_GeomFromText('POINT(-7.808249851904086 49.60307619397752)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (971, 'manor', 'manor', 'e627c5e94513dacbcda181613bfb4a05', ST_GeomFromText('POINT(-6.95290556842991 49.88454396722463)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (972, 'The Bril Forge', 'inn', '70f134498597eda6d86a936df545843a', ST_GeomFromText('POINT(-6.445115426525713 49.803042711380705)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (974, 'The Éadcwén Mare', 'inn', 'ab37006cce9931a5d0fefa06a909747e', ST_GeomFromText('POINT(-6.307447876942798 49.51230978759738)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (975, 'manor', 'manor', '5a8e3a00c7a8d68e386bd306eb383b5d', ST_GeomFromText('POINT(-6.801332894078707 49.70084105801921)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (976, 'Caras Denethora', 'village', 'An Elvish flet-village of central Harlindon, founded before the rising of the Sun by Danitharo — last king of the Green Elves. Hidden in the trackless ancient woods, it survived the Orc hunts of the First Age unscathed. In the Third Age it looks much as it did at the end of the First Age: wooden platforms and walkways built high among old trees, connected by rope-bridges, visible only when the lanterns are lit at dusk.', '93bb0145796ef989b735c30c57ada751', ST_GeomFromText('POINT(-7.532914752738256 49.01636703990321)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (977, 'Bar-i-Dinuviel', 'village', 'A fishing village on the coast of Dor Tinuviel, its name meaning ''Home of the Nightingale''. Stone houses with fishing nets hung to dry face a sheltered cove; the people here fish the coastal waters and trade their catch. The village is small and tranquil, known mainly to sailors navigating this stretch of coast.', '8cd324e78bb439fd5727488315a76b7a', ST_GeomFromText('POINT(-6.972918220725228 48.760747581562775)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (978, 'Rond Rhandir', 'village', 'A village on the northern side of Ram Galen, with about fifty families and 300 inhabitants. Most are farmers — liegemen, tenants or small freeholders growing grain and hay. All houses are single-storey stone buildings of one or two rooms, except for the slightly larger two-storey house of the local noble. In winter, the men go to the nearby woods to cut timber, floating logs downstream to mills in the Morthond valley. A market fair is held outside the village after the sheep-shearing.', '38a2f9e1b1dba85cdb2dcc8f4843832b', ST_GeomFromText('POINT(7.139960081413626 42.8889300426459)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (979, 'Corgonin', 'town', 'A small town beside a tributary of the Morthond in the eastern Pinnath Gelin, Corgonin takes its name — ''Circle of Stones'' — from a mysterious monument on a nearby knoll: a tall black obelisk surrounded by a ring of twelve grey menhirs. No one knows its origin, and the locals largely avoid it, though straying sheep occasionally wander inside. The town itself is a major winter gathering point for the Mesta sheep-droves; the wool trade dominates spring life, with shearers filling every house and a great fair held outside the walls.', 'd39427c3ecdaf2b26d3dc778e7f3cd75', ST_GeomFromText('POINT(8.176895341117282 42.31115493851449)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (980, 'town', 'town', '190c825b7d11ff951b9900ef26568f27', ST_GeomFromText('POINT(7.36257363959774 41.67941226638539)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (981, 'Tirith Cobas', 'town', 'An Elvish tower on the western shore of Lond Cobas, founded by Celeborn the Wise as an outpost of Edhellond. It rises atop a tall hill and serves as a lighthouse for passing ships, communicating with Tirith Aear on Dol Amroth across the water by light signals. The tower is used as a meeting place and retreat by the leaders of Edhellond''s kindreds. A traveller approaching by sea sees the light long before the tower itself becomes visible.', '3bcf02da4072227cedde6d5fd6e4ef5d', ST_GeomFromText('POINT(8.598183234329197 41.62295655254813)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, external_id, geom) VALUES (982, 'Rendûl', 'fortified town', 980, '60% Gondorian, 40% Dunnish', 'Occupied by Gondor since at least T.A. 954, granted a royal charter in T.A. 1187.. Regional trading post on the River Morthond; a defense against Dunnish insurrection.. Rendûl is perhaps the best base for exploration of the interior of Anfalas.', '40413711e840fcd21fd4ca8baa709ead', ST_GeomFromText('POINT(8.57815180508654 43.5070406552782)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (983, 'Nineryn', 'town', 'The Nineryn (''Wetwoods'') are two adjoining, marshy woodlands gathering about the upper Morthond. Foot travel through them is difficult due to the boggy ground; the woods are generally avoided by travellers and claimed as a private hunting preserve by the Lord of Mornan. Poaching is heavily fined. No settlement exists here — the Nineryn are a landmark and a warning to those who leave the road.', '407c900373c7b84fd8645dfe5173129f', ST_GeomFromText('POINT(9.116860465244953 44.13098920852048)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (984, 'Dol Faeren', 'town', 'A Gondorian mountain-town set on a lower foothill of the Dwimorberg overlooking the Morthond Vale. Its stone houses cling to the slope; the people here are farmers and shepherds who work the high pastures. The shadow of the haunted Dwimorberg gives the place a subdued quality; locals keep to old customs and do not speak lightly of the heights above.', '33dc871b7cbb15e4c2a91e9f0be1d1f1', ST_GeomFromText('POINT(9.613039494338228 44.808792945141505)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (985, 'Andram', 'town', '6f87148cfbc679d60cf2b96bd472d1bc', ST_GeomFromText('POINT(11.247743584545619 40.811760972482716)', 4326));
INSERT INTO locations (id, name, location_type, description, external_id, geom) VALUES (986, 'Rul', 'town', 'A town in the region, its stone houses and market serving local farming communities.', '9c5ad456482ba2f55dd15dfae0f00a8a', ST_GeomFromText('POINT(22.71094111482394 42.04051328181626)', 4326));
INSERT INTO locations (id, name, location_type, external_id, geom) VALUES (987, 'Estomar', 'town', '51eaec63902d3ff62e258b2afab5b768', ST_GeomFromText('POINT(-12.043793815810359 54.45190209721756)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1045, 'Tolfalas', 'town', 'The island of Tolfalas is a large, remote island guarding the mouth of the Anduin, its geography ranging from rugged coastal cliffs to sheltered inlets. The principal settlement (Gobel Tolfalas) sits at the end of a long firth on the southeastern coast, around a haven that has served as a Gondorian naval base since T.A. 759. Stone houses climb the ridge above the firth; the warden''s small keep overlooks the water. The island''s isolation and strategic position make it a place of passing sailors and military men more than settled farmers.', ST_GeomFromText('POINT(12.155424336886963 38.83683290538081)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1046, 'Ostara', 'town', 'A small Gondorian town of southeastern Belfalas, considered part of the County of Eregost. Its stone houses face the inland hills; the town serves as a minor administrative centre and market for the surrounding farmland and small estates.', ST_GeomFromText('POINT(10.994689211936706 39.71179194827498)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1047, 'Eregost', 'town', 'A harbour-town in southeastern Belfalas and chief settlement of the County of Eregost. Its stone quays face the open waters of the Bay of Belfalas; fishing boats and small trading vessels keep the harbour busy. The town''s houses are whitewashed stone with tiled roofs, and the smell of salt and tar is constant.', ST_GeomFromText('POINT(11.12220976309949 40.01940894137091)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1048, 'Sarlond', 'town', 'A small Gondorian town on the Cape of Sarlond in northeastern Belfalas, between Thonfalas and Eregost. Its stone houses and small harbour face the open waters of the bay; fishing and coastal trade are the main activities. The cape gives good shelter from westerly storms.', ST_GeomFromText('POINT(11.662654003741771 40.350524210017404)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1049, 'Thonfalas', 'town', 'A small coastal town in easternmost Belfalas, on the western part of the Gilrain-Serni bay. Its stone fishermen''s houses face the water; the bay provides good anchorage and rich fishing. The town is a quiet, salt-wind-scoured settlement dependent on the sea.', ST_GeomFromText('POINT(11.802319369301012 40.59304416667464)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1050, 'Nargond', 'town', 'A township of Belfalas on the coastal road, roughly halfway between Ráma and Endil. It is the chief settlement of the county of the same name — a modest Gondorian town of stone houses, fishing boats and small trading vessels. The coastal road keeps it connected to the wider economy of Belfalas.', ST_GeomFromText('POINT(9.825750826277838 40.59765509195068)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1051, 'Rama', 'town', 'A town of Gondor or the coastal region whose character and economy reflect the local geography.', ST_GeomFromText('POINT(9.599583993463288 40.93128500109434)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1052, 'Bar Algund', 'town', 'A small town of western Belfalas, lying close to the great seat of Dol Amroth and within the same Grithion. Bar Algund''s stone houses and small harbour face the Bay of Belfalas; the town relies on fishing and on trade with the Prince''s court nearby.', ST_GeomFromText('POINT(9.211428654258464 41.14256950163231)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1053, 'Galibur', 'village', 280, '100% Dunnish', 'Settled during Númenórean expansion in Gondor, circa S.A. 2500.. An important Dunnish ritual site in central Belfalas peninsula.. Ruins dating to the time of the Daen Coentis lie just north of town.', ST_GeomFromText('POINT(10.60605515125012 40.820328686075634)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1054, 'Emlin', 'town', 'A small fishing village in the southernmost Angle of Lossarnach, where the river Erui meets the great Anduin. Its stone houses and wooden wharves face the confluence; the people here are fishermen who work the rich waters where the rivers meet. Flat-bottomed boats and nets are spread on every bank.', ST_GeomFromText('POINT(17.444037290867254 41.81776630329182)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1055, 'Bar Erui', 'town', 'A mountain hamlet of no more than thirty-five households in the foothills of the Blue Mountains, known as Eruimar or ''Lonely Home''. Though remote, it is easy enough to spot from a distance. Founded as a Dúnedain trading post for trappers and mountaineers, it retains that character in the mid-Third Age, with a small Laughing Brook running through the settlement. The tavern here can fill a long evening with wild tales from the hills.', ST_GeomFromText('POINT(17.242812557772904 42.05394305494517)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1056, 'Imloth Melui', 'town', 'Imloth Melui (''Sweet flower-valley'') is a fertile valley in Lossarnach dotted with small settlements, orchards and herb-gardens. Its principal settlement is Arnach, seat of Forlong the Fat, Lord of Lossarnach. The valley is famous for its roses and healing herbs; a traveller riding through in spring is struck by the colour and fragrance of the terraced slopes. The Hall of the Gentle Hand and the Hall of Lady Vanyalos are known throughout southern Gondor for their healers.', ST_GeomFromText('POINT(16.801591374823325 42.58882090246783)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1057, 'Barad Othnir', 'town', 'A castle and small settlement in northeastern Harithilien, perched on a rocky spur of the western Ephel Dúath. Its tower overlooks the main road below, commanding a view of traffic between Ithilien and Mordor. The castle walls are of dark mountain stone. A small garrison and their families live in the shadow of the keep.', ST_GeomFromText('POINT(18.7738226823858 42.985646316004306)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1058, 'Rianbar', 'town', 'A town of Harithilien, situated south of the Emyn Arnen along the river Dinnen. Its stone houses and market square serve the southern Ithilien farmlands; the Dinnen valley is known for its olive groves and herb gardens, and the town''s small harbour handles river traffic to and from Pelargir.', ST_GeomFromText('POINT(18.287231679035013 42.3630800791496)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1059, 'Tir Ethraid', 'town', 1030, '85% Gondorian, 15% Haradan', 'Settled by Gondorians, circa T.A. 930.. Maintain watch over the Crossings of Poros; a trading site; a defense against Haradan incursions.. Tir Ethraid is the frequent target of Haradan raids, but King Tarondor has pledged a good deal of gold to strengthen the town''s resources.', ST_GeomFromText('POINT(18.071734031143524 40.43043169432147)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1060, 'Aludor', 'town', 'A small town in southwestern Harithilien, set halfway between Hyarpendë and Tir Ethraid on the road through the region. The town is notable as the seat of House Alagdor, one of Ithilien''s ancient noble families, whose home castle Târik-Ûriyat rises on a rocky spur above the surrounding fields and olive groves. Stone houses with tiled roofs line the main road; the air carries the scent of herbs and cultivated terraces.', ST_GeomFromText('POINT(17.151897319624798 40.66003195949049)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1061, 'Bar Nepos', 'town', 'A small town and watchtower at the mouth of the river Nethos in southwestern Harithilien, home of the noble house of Nethos. The tower overlooks the river confluence and the road to Pelargir. The town''s houses are compact and stone-built; the watchtower is the tallest structure for miles.', ST_GeomFromText('POINT(16.859136563949292 40.20720744415561)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1062, 'Bar Morvegil', 'town', 'A small town of Harithilien on a tributary of the Poros, once known as Bar Miruvor (''House of Precious-juice'') and renamed Bar Morvegil (''House of the Black-sword'') when the local noble family took a martial crest. Its stone houses and small river-wharf serve travellers on the Poros road; orchards and herb-gardens cover the gentle slopes around it.', ST_GeomFromText('POINT(15.837569166073639 40.31566815280704)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1063, 'Hyarpendë', 'town', 'The most important trading town of Harithilien, Hyarpendë (''South Slope'' in Quenya) sits on the east bank of the Anduin opposite Pelargir, at the northern end of the Hyarmentie road. A ferry runs every two hours across to Pelargir, usually packed with merchants, horses and goods. The town has grown from a lazy village into a bustling commercial centre: merchants deal in horses and mules, a coach line runs south along the Poros, and the Five Falcons inn feeds the weary (at high prices). At the town centre stands a thirty-foot Númenórean obelisk marking the road''s end.', ST_GeomFromText('POINT(16.339469670247333 41.0834098893621)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1064, 'Sindamos', 'manor', 'A lordly manor in western Harithilien, the main settlement of the county of Glorel. Known in Sindarin as Thindamost (''Grey ascending house''), it sits on a gentle slope above the Ithilien farmlands. The manor house is a Gondorian stone hall with outbuildings and enclosed gardens; the surrounding county is known for olives and herbs.', ST_GeomFromText('POINT(17.525082905112818 41.644181518800565)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1065, 'Trenas', 'manor', 'The seat of Tolfalas'' royal warden and the island''s principal settlement (also known as Gobel Tolfalas). Located at the end of a long southeastern firth, with a haven for warships. Stone houses cluster at the foot of a ridge; the warden''s small keep stands on the slope above. The town grew from a military base into a modest civilian settlement during the Third Age, though it remains a place of soldiers and sailors more than merchants.', ST_GeomFromText('POINT(18.251671159266273 42.02665847289581)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1066, 'Methir', 'village', 500, '70% Gondorian, 30% Haradan', 'Settled by Gondorians, circa T.A. 970.. A trading center in Harondor, supplying and catering to coastal traffic approaching the Ethir Anduin.. Methir was recently sacked by raiding Haradrim, and the town has yet to recover its role as a way-station for river traffic.', ST_GeomFromText('POINT(13.919258724954991 39.90820412818191)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1067, 'Mindo-o-Galad', 'watchtower', ST_GeomFromText('POINT(-2.365252052355574 53.31091547166315)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1068, 'Tir Bronadui', 'manor', 'A Noldor Elvish settlement on the northern coast of Lothlann — the only Elvish community in these chill lands. Originally a village with a tall lamp-house guiding lost sea-farers, it grew into a purely military outpost guarding the route around the Ered Luin into Lothlann and Forlindon. Its stone watchtower is visible for miles along the grey coastline; the Noldor here are few, disciplined and watchful. After the destruction of Angmar (T.A. 1975) the garrison was largely lost trying to rescue Arvedui, and the survivors departed south.', ST_GeomFromText('POINT(-10.439223367744457 55.88520485402478)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1069, 'Annost', 'watchtower', ST_GeomFromText('POINT(-9.527275348496316 54.21506154089465)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1070, 'Sarn Athrad', 'town', 'Sarn Athrad (''Stone Ford'') is the ancient stony ford of the Dwarves over the river Gelion near the influx of the Rathloriel, across which the old Dwarf Road from the Blue Mountains entered East Beleriand. It was here that the Battle of Sarn Athrad was fought between Elves and Dwarves of Nogrod in the First Age. By the mid-Third Age the old ford has been replaced by Edenathrad a little further north; the original ford is a quiet and wild place, remembered in legend but little-visited.', ST_GeomFromText('POINT(-9.788293220140886 52.95741922729997)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1071, 'lovithil', 'manor', ST_GeomFromText('POINT(-10.720558759301552 52.565874754297745)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1072, 'Tol Ramdal', 'watchtower', 'A small island east of the Gulf of Lhûn in southern Forlindon, serving as the main harbour for High Elves setting out on sea-journeys to southern lands. The island''s small stone quay and beacon-tower are maintained by a handful of Elves; the air here carries the salt of the open sea and the faint music of those about to sail west.', ST_GeomFromText('POINT(-11.160772360967522 51.63047749446025)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1073, 'Vorondrast', 'watchtower', 'A watchtower in Forlindon, maintained as part of the system of watch-posts guarding the coasts and passes of this northwestern Elvish realm. Stone-built and exposed to the elements; a small garrison keeps watch.', ST_GeomFromText('POINT(-11.740340792510981 52.3938814207865)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1074, 'Amon Ereb', 'watchtower', 'A lone hill of gentle but commanding slopes in southern Forlindon, the highest point between the Ramdal and the Gelion. In the Third Age, the tower of Car Sidh (''House of Peace'') crowns its summit — seat of Rhiannon, a Mithren noblewoman who patronises the largest house of Eldarin healers in Forlindon. About two hundred Elves dwell here; their halls are bright and ordered, and the terraced slopes bear the faint traces of much older First-Age earthworks. The hill is a landmark visible for miles across the flat southern lands.', ST_GeomFromText('POINT(-10.237892692904689 51.65796643407067)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1075, 'Rhomros', 'manor', 'Rhomros (''Loudfoam'') is a town in Galfalas where the Tauron (Celos) river meets the Bay of Lune. Timber cut from the forests of Forlindon is floated downstream here for ship construction; a small shipyard and sawmill dominate the waterfront. Low stone and timber houses face the bay; the smell of resin and sawdust hangs in the air.', ST_GeomFromText('POINT(-8.006369655528761 51.78831139179079)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1076, 'Mindon Bron', 'watchtower', 'A watchtower at Caranthir''s Pass in Forlindon, maintained by the Rangers of Lindon to guard the route against intruders coming around the Ered Luin. A small garrison keeps the beacon burning; the tower is a plain stone structure on a windswept ridge with a view of the pass below.', ST_GeomFromText('POINT(-8.079277149305724 53.69483588129134)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1077, 'Amon Draug', 'point of interest', 'The highest hill in Forlindon, Amon Draug, sat near the mid-point of the Emyn Cûn hills, where the Gelion began. It was possible to see Belegaer from it’s summit.', ST_GeomFromText('POINT(-11.241786086245078 54.28181404265275)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1078, 'Talanobel', 'town', 'A Nando-Sinda village ruled by descendants of the Guest-elves of Arthorien, Ithilbor''s line. Its name means ''Flet-town''; buildings are set on platforms in the trees above the rapids of a nearby stream which the villagers use for small industries. Light filters through the canopy and the sound of water is constant.', ST_GeomFromText('POINT(-8.602161750883086 50.77731095498936)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1079, 'Cebir Luin', 'ruins', 'A steep rocky hill south of the Pinnath Luin in Forlindon, site of a battle in S.A. 1700. The hill''s flanks are honeycombed with old Dwarven excavations. By the Third Age it is a ruin: overgrown earthworks, dark dripping tunnels, and travellers passing below glancing up at the jagged stone crest with unease.', ST_GeomFromText('POINT(-4.121496894915944 49.984710647829694)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1080, 'Tawarobel', 'village', 'The chief settlement of Dor Lelvin, belonging to the manor of Bar Erui at the end of the Ramb Luin. A village of about 150 individuals, mostly mortals with a small Elvish presence; the manor was long associated with Gildor Inglorion''s line. Stone and timber houses sit at the edge of an old Elven estate whose gardens and orchards are still tended with Elvish care.', ST_GeomFromText('POINT(-5.948079891192394 52.919803642661755)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1081, 'Barad Caranthit', 'ruins', 'A rocky hilltop in Forlindon south of the Pinnath Luin, honeycombed with old Dwarven excavations. The site of a battle in S.A. 1700 where a band of Dwarves and Elves made a last stand against Orcs. By the Third Age it is a ruin: crumbling walls and overgrown earthworks visited only by the bold or the curious. Old stories say one survivor escaped to rouse a Dwarven host — the tunnels go deeper than they look.', ST_GeomFromText('POINT(-6.883275105532636 56.04439167916222)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1082, 'Luithen', 'village', 'A village in Forlindon or the Blue Mountains area, small and quiet; details of its inhabitants and economy are not well documented in current records.', ST_GeomFromText('POINT(-4.830112141215316 49.54394786522112)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1083, 'Entamundo', 'town', 'A town in the region, its character shaped by local geography and economy.', ST_GeomFromText('POINT(2.563137038649836 48.6927128341211)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1084, 'Alclud', 'village', ST_GeomFromText('POINT(-0.248407562149831 47.195886057386254)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1085, 'Cithiel', 'town', 'Once a great township of 4,400 on the Baranduin in Minhiriath. By T.A. 1400 the old town was abandoned. The site has since been resettled on a smaller scale by Eriadorian tribesmen, who call it Cuncan — a rough cluster of timber-and-daub buildings amid the foundations of the much larger earlier settlement.', ST_GeomFromText('POINT(-2.428358283544628 49.31850008112172)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1086, 'Silent Castle', 'ruins', 'Bar Airlossiel (''Home of the Lonely Snow-maiden''), also known as the Silent Castle, is an ancient Elvish tower in a forgotten corner of southern Sîrgala. Its original community of Silvan Elves and Arthadan refugees pledged fealty to a half-Elven mage, Airlossiel the Quiet, who transformed into one of the Houseless after a morgul-wound in T.A. 1409. Her spirit remains bound to the tower''s foundations; the haven became almost eerily peaceful thereafter, and few visitors leave with a full account of what they experienced. Rangers occasionally send incurably wounded men here; some return years later, cured but confused.', ST_GeomFromText('POINT(-2.713613170308578 50.158211634982955)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1087, 'Parth Ainatir', 'point of interest', 'Parth Aertirith (S."Sward of the Holy Watch") was an Elvish camping glade on the border of Sîrgala and Harlindon.The Place was forsaken by the Elves after a great tragedy, the juvenile and drunk Elcaldil of Girithlin, heir of Girithlin, had harassed an elven girl and was thrown down by Glorfindel Goldenhair, after which the House Girithlin thought of it''s family and fate as cursed.', ST_GeomFromText('POINT(-3.241505115625056 49.610776794368)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1088, 'Endrist', 'ruins', 'Once a populous township of 4,600 in western Siragale, known in its heyday as Enedhriss. By the early Third Age it was already in decline; by T.A. 1400 it had been fully abandoned. A traveller today finds only the ghostly outlines of old foundations under the scrub of the Pinnath Luin''s lower slopes — no fire, no voice, only the wind through broken stone.', ST_GeomFromText('POINT(-2.383984129906068 49.69500962840932)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1089, 'Bag end', 'point of interest', 'Built by Bungo Baggins into the Hill above Hobbiton''s Bagshot Row as a wedding gift for his wife Belladonna Took, c. T.A. 2890. The most luxurious Hobbit-hole in the Westfarthing, entered through a perfectly round green door with a bright brass knob. Inside, all rooms are on a single level: bedrooms, kitchens, pantries, studies, wardrobes and dining-rooms arranged along a comfortable tunnel-passage. The best rooms face the garden and meadow to the west. Home of Bilbo Baggins and later his heir Frodo Baggins.', ST_GeomFromText('POINT(-1.244931105219367 51.62852208381378)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1090, 'Bareketta', 'castle', 320, '100% Dúnadan', 'Bareketta is a handsome estate on the eastern shore of Nenuial, the primary seat of the Eketta family — one of the two most powerful noble clans in Arthedain. It was built with beauty as much as defence in mind: graceful stone towers look out over the lake, and the gardens between the walls are carefully tended. The estate is comfortable and well-staffed; those granted admittance find a household that takes hospitality seriously.', ST_GeomFromText('POINT(-0.469623980342106 53.493819717355144)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1091, 'Kuska', 'village', 390, '100% Angmarean (Mixed Mannish: Dunnish, Brygath Easterling, Estaravë)', 'Kuska sits in the Angmar Gap three miles west of Barad Morkai, founded by Angmar''s forces to keep the fortress supplied. The village is a grim place: timber barracks and storehouses surrounded by a rough palisade, populated almost entirely by the mixed Mannish people — Dunnish, Brygath Easterlings, Estaravë — who serve the Witch-king''s armies. Provisions are moved constantly up the road to Morkai; Kuska''s only purpose is to feed the war machine above it.', ST_GeomFromText('POINT(6.520577494896312 55.048951053981135)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1092, 'Ost Galad', 'town', 'An Elvish settlement in the Emyn Lûm area of Mirkwood, known as Ost Galadh (''Tree Fortress''). In the mid-Third Age its population is about 1,200. The settlement is built among the great forest trees, with platforms and walkways of Silvan Elvish craft connecting the living quarters above the ground. The trees here are ancient and vast; a traveller arriving from outside Mirkwood is struck by the quality of the light filtering through the canopy and the utter silence of the undergrowth.', ST_GeomFromText('POINT(17.024039948514115 54.203242899740815)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1093, 'Celebannon', 'village', 110, '95% Silvan Elvish, 5% Sinda', 'Celebannon is a small but elegant Elvish village on the banks of the Taurduin in Mirkwood, founded in the early Third Age as a point of contact between the Elves of the Woodland Realm and the surrounding folk of Rhovanion. Its buildings are finely made — carved wood and white stone among the trees — and the Elves here are more accustomed to the presence of travellers than most of their kin. A small market operates occasionally where Elvish goods can be obtained at fair prices.', ST_GeomFromText('POINT(20.319857781755008 53.400661286504764)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1094, 'Cairg Dinas', 'village', ST_GeomFromText('POINT(-3.122325604648317 47.69541097248639)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1095, 'Limmon', 'village', ST_GeomFromText('POINT(8.620391946119799 42.66736596240788)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1096, 'Calenin', 'village', ST_GeomFromText('POINT(8.310991762662013 42.44778466202531)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1097, 'Doldorth', 'village', 'A village in Gondor''s Ithilien region, a modest settlement of stone farmhouses surrounded by the herb-gardens and orchards for which Ithilien is famed. The traveller arriving here in spring or summer is struck by the fragrance of flowering herbs and the orderly terraces climbing the hillside. Life is quiet; the people grow herbs, olives and grain.', ST_GeomFromText('POINT(6.712816738648292 42.868599310618215)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1098, 'Ost-in-edhil', 'ruins', 0, 'N/A', 'Ost-in-Edhil was the great Elvish city of Eregion, founded in the Second Age by Galadriel and Celeborn and later the home of Celebrimbor the smith, who forged the Great Rings here. Its ruins still show the elegant stonework of the Gwaith-i-Mírdain craftsmen; broken archways and carved lintels half-buried in ivy suggest a settlement of rare sophistication. Nothing now inhabits those fallen halls but wind and the memory of what was lost when Sauron brought the city to ruin.', ST_GeomFromText('POINT(6.10677238379667 48.654335533996736)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1099, 'Cillien', 'village', 145, '100% Dunman', 'Cillien is a Dunnish village in the hills of Enedwaith, the focal point for the scattered families of Clan Eogbann. Its most notable building is the Healer''s Hall — a timber longhouse where the clan''s healers practise their craft, serving anyone in the region who makes the journey here. The village itself is small and self-contained, its longhouses arranged in a rough circle around a shared fire-pit.', ST_GeomFromText('POINT(6.948790388251328 48.286409902662065)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1100, 'Pillars of Stone', 'ruins', ST_GeomFromText('POINT(5.146369766489915 48.698512237463206)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1101, 'Minas Melosse', 'point of interest', ST_GeomFromText('POINT(5.89693339932258 50.07763268808455)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1102, 'Beanach', 'town', ST_GeomFromText('POINT(6.061802976570391 47.938733290407235)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1103, 'Dun Fidach', 'town', 'What was once a Dúnadan fortress called Amon Mîn (''Hill between the gaps'') — a watch-post commanding the Greenway in Dor Wathui — has long since been abandoned. The Rangers of the North maintained it briefly after Arnor''s dissolution, but eventually left it to decay. The Dunlendings call the ruins ''Dinas Gwydd''; a small Ranger campsite occasionally shelters here.', ST_GeomFromText('POINT(5.894414480295413 47.74072678929605)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1104, 'Dun Udrost', 'town', 'Echad Dagoras (''Dagoras'' Camp'') is an old Elvish ruin south of Eregion, some sixty miles southeast of Ost-in-Edhil. The Rangers of the North use it as a temporary camp; the local Dunlendings call it Dinas Yddryst or Dol Du (''Dark toll'') and shun the place. A few broken stone walls and foundation courses amid scrub — eerie in atmosphere.', ST_GeomFromText('POINT(6.650490349003736 48.18247825976938)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1105, 'Creatrach', 'town', 'In the Coit Cerdd on the borders of Dunfearn stands the ruin of an old Gondorian watchtower called Harndirion (''Southwatch''). The Rangers of the North maintain a semi-permanent camp here among the ancient stones. The local Dunlendings call it Craig-y-Din (''Castle Rock'') and give it a wide berth.', ST_GeomFromText('POINT(6.673436505868934 47.79239491928146)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1106, 'Gwâl Draig', 'town', 'A Dunlending village in Dunfearn that grew up around an ancient Temple of Justice, built c. T.A. 1200. The original temple — shaped like a great stone bull''s head, sixty feet tall — now forms the core of a village called Gwâl Draig, home of the Draig-lûth tribe, descendants of the temple''s original adherents. The tribe still bears the Dragon Turukulon as their symbol. The village is a rough settlement of timber houses around the old stone temple; guards in white robes and armed with wide-bladed axes watch the entrance.', ST_GeomFromText('POINT(7.123181180426845 47.82321709794124)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1107, 'Odharn', 'town', ST_GeomFromText('POINT(6.412033209800232 47.70016559791756)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1108, 'Daithen', 'town', 'A Dunnish clan-hold in Dunfearn near the Misty Mountains, its name meaning ''Ancient Fire''. A rough highland village of timber longhouses and livestock pens, ruled by chieftain Menu with the counsel of the local conjurer Selyf Hen. Smoke from fires hangs low in the valley on cold mornings.', ST_GeomFromText('POINT(6.345912011797685 47.4271125180754)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1109, 'Carnach', 'town', 'Ost-Dunhoth was once a township of some 3,200 people in Enedhwaith. By T.A. 1400 its population had drained away entirely. What remains is a field of overgrown ruins — broken walls of old stone half-buried in scrub and grass, with no permanent inhabitants. Local Dunlendings call the place cursed and do not build here.', ST_GeomFromText('POINT(5.744117152828357 47.297529196555374)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1110, 'Golgoch', 'town', ST_GeomFromText('POINT(6.609187266646376 48.007766147957156)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1111, 'Ehuir', 'village', ST_GeomFromText('POINT(4.517626056922889 45.69435931474646)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1112, 'Vervain', 'village', ST_GeomFromText('POINT(5.660664258362598 45.61320566169143)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1113, 'Morven', 'village', ST_GeomFromText('POINT(5.922100751602134 46.02442597016015)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1114, 'Edhellond', 'town', 2400, '80% Silvan Elvish, 20% Sinda', 'Founded by Elves fleeing the Ruin of Beleriand early in the Second Age.. A departure point for Elves leaving Middle-earth.. Edhellond is situated upon a jagged islet at the mouth of the River Morthond.', ST_GeomFromText('POINT(9.215384430306086 41.59827021988721)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1115, 'Maenthirost', 'town', 'A town in the Shire or northern Eriador whose character reflects the modest farming communities of the region.', ST_GeomFromText('POINT(1.315264892540348 54.59761685770499)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1116, 'Witeburg', 'town', 'A small Rohirric settlement near the Hornburg, in the Deeping Coomb about four miles beyond Helm''s Deep and over a mile northwest of the Juggler''s Hall. Its name, ''Castle of Torment'', comes from the oddly shaped hill on which it sits — the Witeberg. Wooden walls and timber longhouses; the men here are farmers and fighters in the Rohirric style, big-boned and hardy, their hall hung with weapons and horse-gear.', ST_GeomFromText('POINT(8.154563988062607 45.38829476087444)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1117, 'Calmirië', 'fortified town', 1200, '80% Gondorian, 20% Dunnish', 'Settled by Gondorian Dúnedain in the early Third Age, granted charter by Atanatar II of Gondor in T.A. 1220.. An economic focus and market town for the province of Calenardhon; the seat of regional administration.. Calmirië is the largest and most cosmopolitan town of the Gondorian territory of Calenardhon.', ST_GeomFromText('POINT(11.052107547861164 44.98777699193615)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1118, 'Calost', 'town', 'A village of Anórien straddling the Calenen stream on the Great North Road, about thirty miles from Calenhad and twelve from Min-Rimmon. The ancient stone bridge over the Calenen is still in excellent repair. Stone houses on the western bank cluster around the Traveller''s Rest Inn, a well-regarded stopping point for anyone on the road. A mill draws from the river; market days bring peasants from surrounding villages.', ST_GeomFromText('POINT(12.299727156058921 44.86176315879172)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1119, 'Astirian', 'village', 'The ancestral manor of House Astorion, a noble Gondorian family of Anórien, on the fringes of the Mouths of the Entwash north of Min-Rimmon. The manor is a solid Gondorian country house of dressed stone, surrounded by extensive farmlands and pastures. The Astorion family has held these lands since the early Third Age; their hall stands as a quiet landmark on the flat green plain.', ST_GeomFromText('POINT(15.545072449264742 44.83558896115036)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1120, 'Bar Duilin', 'town', 'A town of Anórien situated on the Anduin opposite the island fortress of Cair Andros. Its location makes it a natural waystation for soldiers, messengers and supplies crossing to and from the fortress; a garrison camp and a river-landing dominate the waterfront. Stone houses and wooden barracks line the main road leading to the ferry.', ST_GeomFromText('POINT(17.661204530157647 44.14004071824639)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1121, 'Dim Lamedon', 'town', 'A town of Lamedon in Gondor, lying in the valley of the Lamedon river below steep hills. The name ''Dim Lamedon'' references the shadowed character of the valley; the settlement is a modest Gondorian market town of stone houses with slate roofs, serving the scattered farms and pastures of the surrounding uplands.', ST_GeomFromText('POINT(13.115531819348437 42.781053655198875)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1122, 'Tumladen', 'town', 'A town of Gondor in the Lamedon or Lebennin region, a modest Gondorian settlement of stone houses serving the surrounding farming communities.', ST_GeomFromText('POINT(13.747158156868476 42.68137651336026)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1123, 'Bar-Lymen', 'point of interest', 'A self-governing township and Grithion of Lebennin on the middle Gilrain, its name meaning ''Home of the Blue Way''. Stone houses and a small market serve the surrounding farmland. Its autonomy as a Grithion gives it a slightly more independent character than the usual Gondorian village.', ST_GeomFromText('POINT(13.535042129327076 42.15793386224273)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1124, 'Bar Gilraen', 'town', 'A small town of Lebennin on the lower Gilrain, several leagues northeast of Linhir. It is the seat of the noble family of Bar Gilraen, who hold the surrounding county. Neat stone houses with flat or tiled roofs face a central square; the Gilrain''s fertile banks support grain-growing and some wool trade.', ST_GeomFromText('POINT(13.691221460854322 41.91543979242482)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1125, 'Diniath', 'town', 'A village in the County of Gilrain in southwestern Lebennin, the main settlement of the small barony of the same name. Stone houses and a small market square line the road; the surrounding farmland and fishing on the Gilrain tributary support a modest population.', ST_GeomFromText('POINT(12.270652951393377 40.985680068474274)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1126, 'Bar Annuland', 'town', ST_GeomFromText('POINT(13.674276861522001 41.083513694510664)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1127, 'Lindon', 'town', 'An Elvish coastal settlement in Lindon, one of the last Elvish domains in the west of Middle-earth. The settlement is small and quiet — elegant timber-and-stone buildings half-hidden among trees near the shore, maintained by Elves who prefer the company of the sea to that of Men. A traveller is struck by the orderliness and beauty of everything here: tools put away neatly, gardens tended with obvious care, and always somewhere in the background the sound of music or quiet voices.', ST_GeomFromText('POINT(14.301150576455248 41.08018609168526)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1128, 'Lalornen', 'town', 'A town of Lebennin on the middle Serni, halfway between Brethil and Linhir. A modest Gondorian market town of stone houses, it serves the farming communities of the Serni valley and acts as a waystation on the road between the two larger settlements.', ST_GeomFromText('POINT(14.5795769794468 41.491203940931356)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1129, 'Dol Calimir', 'town', 'A town of Lebennin on a small tributary of the Serni, halfway between Minas Brethil and Pelargir. Its position on this route makes it a regular stopping point for travellers. Stone houses and a small inn; in recent years the town has been fortified with a new outer wall.', ST_GeomFromText('POINT(15.57488310345749 41.68432393525742)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1130, 'Barfalas', 'town', 'A small fishing village in Lebennin on the Anduin, southwest of Pelargir. Stone houses with fishing nets hung to dry face a sheltered cove; the people here fish the river and trade their catch at the nearest market. The village is small and tranquil.', ST_GeomFromText('POINT(15.885149223521815 41.119181509105715)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1131, 'Arnbad', 'town', 'A small town in eastern Methed Lebennin, seat of the surrounding Grithion of the same name. Its name — ''Royal Path'' in Sindarin — hints at an old road that once ran through its centre. Stone houses and a modest market hall ring a crossroads shaded by plane trees; the surrounding farmland yields grain and olives.', ST_GeomFromText('POINT(15.201729716218498 41.266272310261506)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1132, 'Pellas', 'town', 'A small Gondorian town or village in eastern Lebennin, about twenty-five miles northeast of Pelargir in the County of Landor. Also known as Barath Tâlhir, it is a freehold estate of House Tâlhir, a local knightly family. Stone houses and a modest manor; grain and livestock are the main produce of the estate.', ST_GeomFromText('POINT(16.539711503431587 41.55459782743415)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1133, 'Minas Airnach', 'town', 'A town of western Lebennin in Gondor, whose stone houses and small market serve the farming communities of the surrounding river valley.', ST_GeomFromText('POINT(16.479045517744957 41.995710026601884)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1134, 'Bar Luindol', 'town', 'A small town of Lossarnach, situated along a tributary of the Erui a few leagues south of Minas Arthoron on the Rathon Gondor. It is the ancestral seat of the noble family of Bar Luindol. Its stone houses and cultivated terraces benefit from the rich soil of Lossarnach.', ST_GeomFromText('POINT(16.719628251727585 42.266084960178034)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1135, 'Echorost', 'town', 'A fortified village of southwestern Lossarnach at the confluence of the Celos and the Sirith, the chief settlement of the county of Enedhîr. Its name — ''Ring-fort'' — reflects its circular defensive layout: stone walls and a central square that serves as market and muster ground. The surrounding farmland of Lossarnach is rich; the village exports grain, wool and the famous roses of the valley.', ST_GeomFromText('POINT(15.870012711995875 42.51707934327671)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1136, 'Barad Dur', 'fortress', 'Raised by Sauron, circa S.A. 1000.. Domination of the plateau of Gorgoroth.. Built on a spur of the Ered Lithui, and fashioned by the power of Sauron''s Ruling Ring, Barad-dûr consisted of a great central tower with nine radial towers connected to it by fortified bridges. No stronger fortress ever existed in Middle-earth. Once the seat of Sauron''s power, Barad-dûr fell when Isildur cut the Ring from Sauron''s hand. Orcs and Trolls now control the area, and no Man has visited Barad-dûr since the Plague.', ST_GeomFromText('POINT(21.456739666583342 44.250923912144174)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1137, 'Barad Wath', 'castle', 'Gondor began construction on the tower after the fall of Sauron, but abandoned it to conserve resources.. Monitoring traffic between Nurn and Gorgoroth.. The tower rests high in the Eregwath, providing a view for many leagues in many directions.', ST_GeomFromText('POINT(21.456966514449896 42.44558701172102)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1138, 'Danwaith', 'town', ST_GeomFromText('POINT(-4.475943181526394 48.69499314721522)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1139, 'Hyarlindunt', 'town', 'A town in northern Forlindon, its position and character shaped by the cold winds of the northern coast and the sparse population of these lands.', ST_GeomFromText('POINT(-4.624105749297354 48.842909358271754)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1140, 'Burh Beorills', 'town', 'The seat of the Berilas clan along the Men Rómen in the hills of Duil Rewinion, known in Rohirric as Berilabaurg or ''Little-bears'' Town''. A stockaded Northman settlement of timber halls and longhouses; its cattle-pens and storehouses sit behind a wooden palisade. The Berilas are tough hill-folk; their hall is hung with bear-skins and old weapons.', ST_GeomFromText('POINT(21.927226132808812 47.51460949965142)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1141, 'Angrenost', 'citadel', 3000, '100% Gondorian', 'Angrenost — known to later ages as Isengard — is a Gondorian fortified complex in the Gap of Calenardhon, its defences centred on the indestructible tower of Orthanc. A vast circular wall one mile in diameter encloses the Orthanc and its surrounding grounds; no siege weapon has ever damaged either the tower or the ring-wall. The fortress administers the northwestern approaches to Gondor and maintains a watch on all movement through the Gap.', ST_GeomFromText('POINT(7.669299713818591 47.09796179869919)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1142, 'Tir Serni', 'town', 'A town and castle of Lebennin on the lower Serni, about 45 miles east of Linhir. Its position on the Serni makes it a waystation for river traffic; the castle overlooks the water from a low promontory. The town''s stone houses and small market serve the Serni valley farmers.', ST_GeomFromText('POINT(14.027355981402826 41.33515014810564)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1143, 'Ostigrurth', 'fortress', 'Built by Sauron in the mid-Second Age.. Control of traffic in the Den Nurn; the manufacture of finished products; small-scale trade.. Ostigurth is situated at the head of a small canyon on the southern edge of Gorgoroth.', ST_GeomFromText('POINT(22.875519871496607 42.977404711698476)', 4326));
INSERT INTO locations (id, name, location_type, inhabitants, description, geom) VALUES (1144, 'Minas Dûrlith', 'tower', 'Orcs (?)', 'Crafted by Sauron sometime during the Second Age.. Control of the plain known as Gaer Dûrlith.. Minas Dûrlith is one of the few Sauronic strongholds to survive the invasion of Mordor by the Last Alliance of Elves and Men.', ST_GeomFromText('POINT(23.365203450960628 44.218531095573496)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1145, 'Cirith Gorgor', 'point of interest', 'Cirith Gorgor (S. "Haunted Pass") was a high pass where the mountain ranges of the Ered Lithui and Ephel Dúath met in the far north-western corner of Mordor. The pass opened out into the mountain vale of Udûn, and was guarded from the beginning of the Third Age by the Towers of the Teeth. When Sauron returned to Mordor c. TA 2951 the Morannon was rebuilt across the Pass.', ST_GeomFromText('POINT(19.273144741103273 45.28455594441935)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1146, 'Cirith Ungol', 'fortress', 124, '97% Gondorian, 3% Mixed Mannish', 'Cirith Ungol is a Gondorian fortress high in the Ephel Dúath, built to watch the Morgai and the Plateau of Gorgoroth from a commanding vantage point. Its towers stand on a narrow pass above the road into Mordor; the view from its battlements encompasses a vast dark landscape of ash and broken rock. The garrison is small and dwindling — King Tarondor has considered abandoning the post — but for now, the Gondorian flag still flies above the gate.', ST_GeomFromText('POINT(19.49113858706461 43.55763235778517)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1147, 'Núrumurl', 'town', 'A town in the Mordor borderlands or Nurn region, its character shaped by proximity to the dark power of that land. Life here is hard and closely controlled.', ST_GeomFromText('POINT(21.08551492330894 40.548706263081066)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description, geom) VALUES (1148, 'Barad Harn', 'town', 560, '70% Haradan, 30% Gondorian', 'Founded in T.A. 1256 on the ruins of a previous town destroyed by a hurricane.. Support for the local trade and fishing industry; a locus for Gondorian power in Harondor.. The southernmost outpost of exclusively Gondorian authority. As might be expected, Haradan raids upon this outpost are frequent and brutal. The Governor commits much of his finances to keeping the walls around Barad Harn secure.', ST_GeomFromText('POINT(13.233507436729269 38.456224230998565)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1149, 'Carondor', 'castle', ST_GeomFromText('POINT(3.284193630903393 54.46168168536261)', 4326));
INSERT INTO locations (id, name, location_type, geom) VALUES (1150, 'Minas Foros', 'castle', ST_GeomFromText('POINT(1.068779671341359 54.90154914317711)', 4326));
INSERT INTO locations (id, name, location_type, description, geom) VALUES (1151, 'Barad Formen', 'tower', 'A tower of the northern Shire or Arthedain region, its function as a beacon or garrison post defining its character. A plain stone structure on elevated ground.', ST_GeomFromText('POINT(1.462763793844177 54.83816740052848)', 4326));
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1159, 'Aglarond', 'cavern', 20, '100% Gondorian (Dúnadan)', 'A second entry for Aglarond — the cavern refuge and storehouse in the White Mountains used by the garrison at Ostiras. Its gem-deposits and storage halls are maintained in readiness for emergencies.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1160, 'Amrûnaur', 'fortress', 180, '100% Gondorian', 'A second fortification in the Dor-en-Ernil pass bearing the same name as Amrûnaur to the south — a commanding position on a rocky shelf, with lightning rods on its towers and a watchful garrison that monitors movement through the mountain route.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1161, 'Andrath', 'ruins', 0, 'N/A', 'Andrath was founded in T.A. 860 by Thorondur of Cardolan and served as the administrative seat of the Prince of Dol Tinare; it has been ruined and rebuilt many times. Most recently it was sacked by King Broggha''s Hillmen. The ruins that remain are a palimpsest of different building periods — Arnorian stonework, Cardolani additions, and hasty Hillman repairs — now largely abandoned.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1162, 'Angsûl', 'fortress', 200, '90% Angmarean, 10% Orcish', 'Completed by the Witch-king in T.A. 1349.. Control of traffic into and out of Angmar.. The Witch-king keeps a large garrison stationed in Angsûl to watch for spies attempting to penetrate Angmar''s central plateau.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1163, 'Ardûmir', 'fortress', 310, '40% Coastal People, 30% Haradan, 25% Corsair, 5% Black Númenórean', 'Built by Númenórean colonists, circa S.A. 3290.. A rural stronghold for a Captain of Umbar; administration of the surrounding lands; guards entry into the Bay of Umbar.. The castle''s eastern curtain wall drops directly into the lake that partially surrounds Ardûmir.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1164, 'Argonath', 'point of interest', 0, 'N/A', 'The Argonath are two colossal figures of Isildur and Anárion carved into the cliffs flanking the chasm at the northern entrance to Nen Hithoel, completed in T.A. 1340 by Romendacil II to mark Gondor''s northern border. The figures stand with raised hands in a gesture of forbiddance toward the north; their faces are stern and ancient-seeming even for statues only centuries old. Travellers approaching by river fall silent when they come into view — the scale is humbling.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1165, 'Barad-dûr', 'ruins', 0, 'N/A', 'Barad-dûr was Sauron''s great stronghold on a spur of the Ered Lithui, fashioned by the power of the One Ring. Its ruin after the Last Alliance was total — the ring-energies that sustained it departed with Sauron''s defeat — yet even the broken remains are vast and dark, far larger than any other structure in Mordor. No one inhabits the ruins; they are avoided even by Orcs, who feel the absence of their master''s presence as a wound.');
INSERT INTO locations (id, name, location_type, inhabitants, description) VALUES (1166, 'Barad-wath', 'ruins', 'Orcs (?)', 'Barad Wath is an unfinished Gondorian tower built to monitor traffic between Nurn and Gorgoroth, begun after the fall of Sauron and abandoned when resources ran short. Its dark stone walls rise only partway to their intended height; the scaffolding marks are still visible. The structure stands as a monument to Gondor''s ambitions in Mordor — imposing in outline but hollow inside, increasingly neglected.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1167, 'Barak-shathur', 'village', 240, '100% Naugrim', 'Founded by settlers from Azanulinbar-dûm c. T.A. 1490.. Exploitation of the mineral resources of the Iron Hills.. The Khuzdul name of the stronghold is thought to mean ''Axe Mountain'' in the Westron.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1168, 'Bar-en-tinnen', 'village', 240, '100% Gondorian', 'A second Bar-en-tinnen settlement entry (see id=1183) — a village on the east bank of the Anduin around a mill on the Sir Tinnen, providing fish and farm-produce trade for inland communities.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1169, 'Bar Lithyrn', 'village', 1000, '70% Donaen, 30% Gondorian', 'A duplicate entry for Bar Lithyrn — a Gondorian silver-mining village on the northern Ered Lithui, in slow decline as the ore veins thin (see id=1184).');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1170, 'Belegost', 'ruins', 0, 'N/A', 'Belegost was one of the two great Dwarf-cities of the Ered Luin, founded before the Sun and Moon first rose. It was destroyed at the end of the First Age when the mountains were broken in the War of Wrath. Its ruins lie buried deep beneath fallen rock and centuries of debris; a few bold Dwarven explorers have recently begun probing the outer passages in hopes of recovering ancestral artefacts, but the deeper halls remain inaccessible.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1171, 'Bottoms Bridge', 'village', 85, '95% Northman, 5% Dúnadan', 'Bottoms Bridge is a small Northman village on a low island at the edge of the Gladden Marshes, founded in the mid-Third Age to supply traders using the Anduin. Its timber bridges connect it to the bank; the sound of the river is constant and the smell of marsh-grass and damp wood is ever-present. The few dozen inhabitants live by fishing and by managing the river traffic that passes through.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1172, 'Bridge Of Stonebows', 'bridge', 0, 'N/A', 'Built by Arthedain, T.A. 1102.. Passage across the River Baranduin on the Great East Road.. The King of Arthedain grants the Hobbits the right to collect a toll, which they keep at a modest few copper coins.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1173, 'Buhr Ailgra', 'fortified town', 220, '100% Northman', 'Founded by Éothraim, circa T.A. 1380.. Defense against Easterling attacks, a trading center for Eothraim.. Buhr Ailgra is one of the few permanent settlements of the Eothraim, who follow the migrations of their herds through the plains of Rhovanion. The town is a simple settlement of thatch and turf houses surrounded by a stout earthen rampart.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1174, 'Aglarond', 'cavern', 20, '100% Gondorian (Dúnadan)', 'Aglarond is a system of extensive caverns in the northern slopes of the White Mountains, currently used as a refuge and storehouse for the garrison at nearby Ostiras. First sheltered by Númenórean settlers long ago, the caves have never been fully explored — deeper galleries glitter with untouched gem deposits that serve as an emergency financial reserve for Gondor''s kings. The entrance is carefully guarded and not advertised.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1175, 'Amrûnaur', 'fortress', 180, '100% Gondorian', 'Amrûnaur is a Gondorian castle on a rocky shelf projecting from the mountain called Thoredarb by the Eredrim, commanding the central pass of Dor-en-Ernil. The fortress is notable for its lightning rods — iron spikes mounted on the towers to deflect the violent storms that frequently pass through the pass. The Dunnish population of the surrounding hills views the garrison with wariness; the castle in turn keeps a close eye on movement through the pass.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1176, 'Andrath', 'ruins', 0, 'N/A', 'A second ruined Andrath entry — the same site as id=1161, the administrative centre of Cardolan repeatedly sacked and rebuilt. In the mid-Third Age it is another ruin, its stones reused by whoever currently occupies the area.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1177, 'Angsûl', 'fortress', 200, '90% Angmarean, 10% Orcish', 'Completed by the Witch-king in T.A. 1349.. Control of traffic into and out of Angmar.. The Witch-king keeps a large garrison stationed in Angsûl to watch for spies attempting to penetrate Angmar''s central plateau.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1178, 'Ardûmir', 'fortress', 310, '40% Coastal People, 30% Haradan, 25% Corsair, 5% Black Númenórean', 'Built by Númenórean colonists, circa S.A. 3290.. A rural stronghold for a Captain of Umbar; administration of the surrounding lands; guards entry into the Bay of Umbar.. The castle''s eastern curtain wall drops directly into the lake that partially surrounds Ardûmir.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1179, 'Argonath', 'point of interest', 0, 'N/A', 'Finished in T.A. 1340 by Romendacil II.. Designation of the northern boundary of Gondor.. Carved rocks flanking the chasm at the northern entrance to Nen Hithoel. The figures represent Isildur and Anárion. Since the time of Romendacil II, Gondor''s northern border has moved even farther north, making the pillars obsolete. Nonetheless, they are a magnificent spectacle.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1180, 'Barad-dûr', 'ruins', 0, 'N/A', 'Raised by Sauron, circa S.A. 1000.. Domination of the plateau of Gorgoroth.. Built on a spur of the Ered Lithui, and fashioned by the power of Sauron''s Ruling Ring, Barad-dûr consisted of a great central tower with nine radial towers connected to it by fortified bridges. No stronger fortress ever existed in Middle-earth. Once the seat of Sauron''s power, Barad-dûr fell when Isildur cut the Ring from Sauron''s hand. Orcs and Trolls now control the area, and no Man has visited Barad-dûr since the Plague.');
INSERT INTO locations (id, name, location_type, inhabitants, description) VALUES (1181, 'Barad-wath', 'ruins', 'Orcs (?)', 'Gondor began construction on the tower after the fall of Sauron, but abandoned it to conserve resources.. Monitoring traffic between Nurn and Gorgoroth.. The tower rests high in the Eregwath, providing a view for many leagues in many directions.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1182, 'Barak-shathur', 'village', 240, '100% Naugrim', 'Founded by settlers from Azanulinbar-dûm c. T.A. 1490.. Exploitation of the mineral resources of the Iron Hills.. The Khuzdul name of the stronghold is thought to mean ''Axe Mountain'' in the Westron.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1183, 'Bar-en-tinnen', 'village', 240, '100% Gondorian', 'Bar-en-tinnen is a small village on the east bank of the Anduin, grown up around a mill on the Sir Tinnen stream. Founded around T.A. 1512, it provides inland communities with fish and serves as a modest trading point for local farmers. The mill wheel turns constantly; the smell of grain and river-mud is constant.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1184, 'Bar Lithyrn', 'village', 1000, '70% Donaen, 30% Gondorian', 'Bar Lithyrn is a mining village on the slopes of the northern Ered Lithui, founded by Gondorian commercial interests to extract silver ore from the mountains. Most inhabitants are local Donaen men lured by the prospect of wages; their Dúnadan lords ship the silver south to Gondor''s treasuries. The village is isolated and in slow decline — the silver veins are thinning, and each year a few more families leave for easier lives elsewhere.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1185, 'Belegost', 'ruins', 0, 'N/A', 'The First Age, possibly before the Sun and the Moon first rose.. Exploit the riches of the Ered Luin, defense against all enemies.. A few bold Dwarven explorers have recently begun to explore the ruins in hopes of finding the artifacts of their ancestors.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1186, 'Bottoms Bridge', 'village', 85, '95% Northman, 5% Dúnadan', 'Settled circa T.A. 1337.. A supply center for traders sailing on the Anduin.. Bottoms Bridge is located on a small island at the edge of the Gladden Marshes.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1187, 'Bridge Of Stonebows', 'bridge', 0, 'N/A', 'Built by Arthedain, T.A. 1102.. Passage across the River Baranduin on the Great East Road.. The King of Arthedain grants the Hobbits the right to collect a toll, which they keep at a modest few copper coins.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1188, 'Buhr Ailgra', 'fortified town', 220, '100% Northman', 'Buhr Ailgra is one of the few permanent settlements of the Éothraim, a fortified town on the lower plains of Rhovanion enclosed by a stout earthen rampart. Most of its residents use it as a seasonal base, following their herds through the rest of the year; the town is most crowded in winter and nearly empty in midsummer. Thatch-and-turf houses cluster inside the rampart; the permanent residents are traders and craftsmen who supply the Éothraim when they return.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1189, 'Aradhrynd', 'manor', 500, '93% Silvan Elvish, 7% Sinda', 'Aradhrynd is the great underground palace of King Thranduil of the Woodland Realm, carved beneath a hill near the northern edge of Mirkwood after the growing Shadow of Dol Guldur made the southern forest uninhabitable. Unlike the dark tunnels of Goblins, the halls are bright with torchlight and alive with Elvish voices; carved pillars support high ceilings, and a river runs through the lower levels. Visitors are rare and rarely welcome — the guards are watchful, and the gates of great iron and oak are seldom opened for strangers.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1190, 'Azanulinbar-dûm', 'dwarven mine', 480, '100% Naugrim', 'Azanulinbar-dûm is the principal mansion of the Dwarves of the Iron Hills and the seat of Lord Fulla III. First delved around T.A. 1000, it has grown into a full Dwarven settlement of homes, workshops and mines beneath the Emyn Angren. Outsiders are rarely admitted; those few who have seen the interior describe halls of bare stone brightened by crystal formations, and the constant sound of industry echoing from every gallery.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1191, 'Bridge Of Mitheithel', 'bridge', 0, 'N/A', 'Built by Arnor, T.A. 320.. Passage across the Mitheithel on the Great East Road. The Last Bridge, so-named because it is the farthest east on the Road, was built of stone with three great arches.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1192, 'Buhr Fram', 'town', 0, '100% Northman', 'Name given to Wraecaburg after the Éothraim settled there in the nineteenth century of the Third Age.. Settlement of Éothraim.. Name given to Wraecaburg after the Éothraim settled there in the nineteenth century of the Third Age.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1193, 'Buhr Mahrling', 'fortified town', 490, '50% Northman (Éothraim), 50% Easterling', 'Buhr Mahrling is a Northman trading town on the lower River Celduin, seized from Easterlings in T.A. 1503. Most residents are seasonal Éothraim who use it as a base between their herding migrations; a sizeable community of Esgaroth Northmen maintain it as an advance trading outpost near Dorwinion. The result is a busy, polyglot town where Éothraim horse-traders, Northman merchants and the occasional Easterling trader haggle across a language barrier.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1194, 'Buhr Waldmarh', 'fortified town', 1250, '100% Northman', 'Founded by Northmen, circa T.A. 1290.. A stable base for the Withras clan; an economic focus for the surrounding farms.. This typical Northman town has many timber longhouses and an earthen dike surmounted by a wooden palisade.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1195, 'Buhr Widu', 'fortified town', 520, '100% Northman', 'Founded by Vidugavia in T.A. 1249.. A center for administration for the Waildung clan; a collecting point for the surrounding Gramuz farms.. Buhr Widu, by the side of the small lake known as Woodmere, retains some of the royal splendor from the time of Vidugavia.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1196, 'Caldur', 'fortress', 210, '50% Coastal People, 20% Corsair, 20% Haradan, 10% Black Númenórean', 'Raised by the Captains of Umbar c. T.A. 520.. A base for sorties against Gondor; administration of the lands around the northern entrance to the Bay of Umbar.. Caldûr is located on a steep outcropping on the northern penninsula guarding the Nen Umbar.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1197, 'Carach Angren', 'keep', 50, '100% Gondorian', 'Carach Angren is the great iron gate that closes the pass between Udûn and Gorgoroth, its original Second Age construction by Sauron destroyed by the Last Alliance and rebuilt by Gondor in T.A. 42. The gate and its flanking walls completely block the pass; without permission to pass through, there is no way from Udûn into the interior of Mordor. The Gondorian garrison here is among the most unusual postings in the realm — surrounded on three sides by Mordor.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1198, 'Caras Amarth', 'ruins', 0, 'N/A', 'Caras Amarth was the first palace of the Woodland Realm, built by King Oropher deep in the forest — a network of caverns carved into a hillside, lit within by lanterns. When Thranduil moved his court northward to the Aradhrynd, Caras Amarth was abandoned; by the mid-Third Age the forest has grown back over the old entrances and only the oldest Elves remember exactly where they lie.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1199, 'Caras Gwindor', 'fortified town', 120, '75% Gondorian, 25% Mixed Mannish', 'Settled by Gondorians around T.A. 1098.. Supply station for caravans in Rhovanion and the garrison at Tir Nindor; surveillance of the Dead Marshes.. Caras Gwindor controls most of the trade between Dagorlad and the Anduin, but its isolation limits its size.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1200, 'Caras Tolfalas', 'village', 520, '100% Gondorian', 'Claimed by Gondor since S.A. 3321; first settled by royal command in T.A. 934.. Subsidized by Gondor''s King more to maintain a claim on the Isle of Tolfalas than for economic reasons.. A poor harbor limits access to this town, but it is the only sure mooring on Tolfalas.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1201, 'Cor Angálaladh', 'cemetery', 0, 'N/A', 'Used originally by Edain and ancestors of the Northmen in the First Age.. A ritual burial ground, now disused.. The site, now darkened within Mirkwood, was once one of the holiest of Northman sites.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1202, 'Creb Durga', 'fortress', 210, '20% Troll, 80% Mixed Mannish', 'Creb Durga was carved by the Warlord''s Trolls from a craggy hill about seventy miles north of Sudúri — a hidden base for raids across central Cardolan. Its location is deliberately obscure; travellers in the region have disappeared without explanation, taken by the Warlord''s parties operating from this base.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1203, 'Crossroads Of The', 'crossroads', 0, 'N/A', 'First mentioned in the time of King Anárion.. A landmark for travellers in Ithilien.. The Crossroads are the junction of the road between Osgiliath and Minas Ithil with the Morannon-Harad Road.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1204, 'Derndingle', 'cultivated glade', 0, 'N/A', 'Used by Ents since the First Age.. A place of gathering and debate.. Derndingle is a dish-shaped valley with a small, tree-topped mound in the center.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1205, 'Dundok', 'village', 150, '100% Stoor Hobbit', 'Dundok is a Stoor Hobbit village hidden in the drier edges of the Gladden Fields, occupied since at least T.A. 1360. Its low-roofed smials and reed-thatched houses are almost invisible among the reeds and sedge grass — which suits the inhabitants perfectly, as they have little desire for outside visitors. The village sustains itself through small-scale agriculture and the fishing of the Gladden''s quieter channels.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1206, 'Durthang', 'citadel', 240, '100% Gondorian', 'Durthang rests on a precarious ledge high above Udûn, giving its Gondorian garrison an excellent view of any movement across the plain below. Built by Isildur in T.A. 1, it is an uncomfortable posting — the winds off the Ephel Dúath are cold and bitter, the views are spectacular and grim, and the isolation is total. Supplies must be hauled up by ropes from the road below.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1207, 'Dûsalan', 'town', 1900, '60% Coastal People, 35% Haradan, 5% Black Númenórean', 'Settled by entrepreneurs from Umbar in roughly T.A. 307.. A mercantile hub for traffic to and from the South.. Dûsalan is a coastal town ruled by three independent Black Númenórean lords but dominated by Umbar.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1208, 'Eilenach', 'watchtower', 120, '100% Gondorian', 'Current tower completed in T.A. 522.. A link in Gondor''s chain of communication with the North.. Eilenach is located on the tallest and steepest hill within Druadan Forest.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1209, 'Eithel Celebrin', 'fortified town', 140, '70% Gondorian, 30% Mixed Mannish', 'Settled by trading company from Pelargir, circa T.A. 1290.. Reprovisioning caravans near the eastern rim of the Dead Marshes.. Eithel Celebrin suffers from the growing tendency of merchants bound for Rhovanion to ship their goods by means of the safer route up the Anduin.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1210, 'Eldanar', 'castle', 288, '100% Angmarean (Mixed Mannish)', 'Built by Númenórean colonists around S.A. 2800, seized by Angmar in T.A. 1325.. An advance watch-station for Angmar.. Built originally by the Dúnedain of Rhudaur, Eldanar is now a secure watch-station set well out into the plain known as the En Udanoriath.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1211, 'Erädas', 'castle', 200, '50% Coastal People, 20% Haradan, 20% Corsair, 10% Black Númenórean', 'Erädas is a Gondorian castle on a sheltered cove in the Bay of Umbar — built by Eärnil I and later seized by Umbar in T.A. 1449. It now serves as a rural retreat for Lord Teldûmeir and as the seat of local administration. The stone battlements look out over a blue harbour; the Coastal People, Haradan and Corsair inhabitants give it a character quite unlike any Gondorian fortress further north.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1212, 'Erebor', 'dungeon', 0, 'N/A', 'Natural formation, enlarged by Dwarves in Second Age (?).. Unknown.. Many tunnels and caverns lie underneath the Lonely Mountain near the town of Dale in northern Rhovanion.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1213, 'Erelas', 'watchtower', 85, '100% Gondorian', 'Construction begun on the site of an older, simpler signal-platform in T.A. 494.. A link in Gondor''s northern chain of communication.. Erelas is the fourth beacon in the series running northwest from Minas Anor.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1214, 'Fennas Drúnin', 'fortified town', 430, '50% Cardolani, 30% Dunnish, 20% Eriadoran', 'First settled by Númenóreans from Tharbad around S.A. 2910.. A social and economic focal point for the farms and villages of Feotar.. A Council runs most affairs in the town, which relies upon the local farms and vineyards for its prosperity.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1215, 'The Forsaken Inn', 'inn', 15, '80% Dunnish, 20% Hillman', 'In business since T.A. 1412.. Reprovisioning and boarding of travellers on the Great East Road at the Mitheithel Bridge.. Operated by a family of Dunlendings, the Forsaken Inn is one of the few safe and neutral places an innocent traveller may rest on the road from Rivendell to Bree.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1216, 'Goblin-town', 'city', 3100, '70% Orcish, 5% Troll, 25% Mixed Mannish Slaves', 'Goblin-town is a vast maze of natural caverns near the High Pass, occupied by Orcs since at least the Second Age. The tunnels connect Imladris to the eastern lands and give the Goblins an unmatched ability to ambush travellers crossing the Misty Mountains. Those who have entered and escaped describe a stench of smoke and filth, crowded galleries lit by smoky torches, and the constant noise of Orc voices. The Great Goblin rules here by fear and brute force.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1217, 'Haudh-in-gwanur', 'burial', 0, 'N/A', 'Originally created in the Second Age to house the noble dead among the Men of Twilight.. A ritual burial ground, no longer in use.. Extensive ruins mark the burial place of Bel''zordin, a prince who was slain in times before the Númenóreans came east to found colonies.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1218, 'Hobbiton/bywater', 'village', 360, '50% Harfoot, 40% Fallohide, 10% Stoor', 'Settled during the migrations of Hobbits to the Shire, T.A. 1601-1610.. An agricultural and pastoral community.. Set on the Great East Road, Hobbiton sees more strange travellers than most of the rural areas of the Shire.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1219, 'Ilanin', 'town', 360, '80% Easterling, 20% Northman', 'Traditional trading site since at least T.A. 950.. A site for commerce; a gathering spot for many Easterling tribes.. Ilanin has few permanent buildings. Most structures are simple tents which disappear as soon as a market ends.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1220, 'Isigir', 'castle', 210, '60% Coastal People, 25% Corsair, 10% Haradan, 5% Black Númenórean', 'Isigir is a castle on the north shore of the Nen Umbar, its surroundings known for the pungent medicinal herbs that grow in the warm lowland soil. Built by the Captains of Umbar in the early Third Age, it serves as the rural power base of Lord Adûmir and administers the productive farmlands around the lake. The herb-gardens are its most distinctive feature; their smell reaches the traveller well before the castle walls are visible.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1221, 'Kas Marzûk', 'town', 1600, '80% Haradan, 20% Corsair', 'Settled by Gondorians around T.A. 932, occupied by Corsairs in T.A. 1448.. A mercantile center near the mouth of the Harnen; a base for Haradan raids against Gondorian holdings in Harondor.. Kas Marzûk was once a Gondorian town known as Caras Mirilond, but it now rests under the authority of Sangahyandim.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1222, 'Kas Shadoul', 'town', 2700, '85% Haradan, 15% Corsair', 'Original town walls built by Ar-Pharazôn around Second Age 3261, deserted then resettled by Haradrim in the early Third Age.. A mercantile center on the south bank of the Harnen; a gathering point for many tribes of Harad.. Kas Shadoul is a major shipping port, and it is also the source for many of the contraband goods which flow into southern Gondor.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1223, 'Kas Shafras', 'town', 1900, '40% Coastal People, 40% Haradan, 20% Corsair', 'Settled by Haradrim around T.A. 800.. A trading port, roughly halfway between the Ethir Anduin and the City of Umbar.. Kas Shafras is renowned for the rare medicinal herbs grown in its environs.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1224, 'Larach Duhnnan', 'town', 420, '90% Dunnish, 5% Dúnadan, 5% Other Mannish', 'Established as an outpost on the Old North Road, T.A. 3; taken over by Dunlendings, T.A. 275.. An urban center for the scattered Dunnish tribes; a neutral place of contact for negotiation.. Larach Duhnnan is in the territory claimed by Clan Feargan, but the foreign traffic passing through it makes it an excellent place for neutral discussion and trade.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1225, 'Londaroth', 'ruins', 50, '100% Northman', 'Settled by Northmen around T.A. 900.. Portage river traffic around the falls at Lindal.. Only a small trading station, two mills, and an inn remain to serve the merchants who must portage their wares over the Falls of Celduin.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1226, 'Lond Ernil', 'city', 10200, '90% Gondorian, 10% Mixed Mannish', 'Site of an Elvish watch-tower, built c. S.A. 3440; city planned and constructed by Dúnedain, c. T.A. 830.. Seat for the Prince of Dor-en-Ernil; harbors and building yards for Gondor''s navy; a mercantile center.. The city guards one of Gondor''s safest harbors, holding the realm''s largest fleet outside of Pelargir.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1227, 'Maethelburg', 'fortified town', 1200, '90% Northman, 5% Gondorian, 5% Other', 'Built by Northman settlers in roughly T.A. 1020.. A focal point for Northman political, social, and economic activity in the Nan Anduin.. Due to its central position, Maethelburg controls virtually all trade in the upper Anduin valley.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1228, 'Marös', 'castle', 150, '30% Coastal People, 30% Corsair, 30% Haradan, 10% Black Númenórean', 'Marös occupies a promontory jutting into the Bay of Umbar — a Númenórean-built castle that has watched the bay''s traffic for over two thousand years. The sea breaks directly against its lower walls at high tide. Its current lord is Borathôr of Umbar; the mixed population of Coastal People, Corsairs and Haradan give the place a rough, polyglot character.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1229, 'Minas Anor', 'fortified town', 45000, '95% Gondorian, 5% Other', 'Founded by Anárion in S.A. 3320, rebuilt by Ostoher in T.A. 420.. Capital and royal residence of Gondor; location of a Palantír; the burial place of Gondor''s Kings.. Minas Anor is situated on a great spur of rock at the eastern tip of the White Mountains.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1230, 'Morannon', 'keep', 300, '100% Gondorian', 'Built by Sauron in the Second Age.. Control of passage into or out of Mordor.. During the Battle of Dagorlad, Sauron was forced to retreat to Barad-dûr when the forces of the Last Alliance broke the defenses here.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1231, 'Morthondost', 'fortified town', 650, '80% Gondorian, 20% Dunnish', 'Built by Dúnedain in the late Second Age, granted autonomy in T.A. 569.. Protection and administration of the Morthond Vale; exploitation of mineral resources.. Despite its proximity to the notorious Paths of the Dead, the Morthond Vale remains an important mining center for Gondor.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1232, 'Mount Gundabad', 'fortified town', 14100, '78% Orcish, 20% Human Slave, 2% Troll', 'Orcs have occupied the Mountain since the Ruin of Beleriand.. The capital of the Orcish realm of Gundabad; a military base for operations in Rhovanion.. Mount Gundabad faces the peak Ügûlai across the Den Lóke, the gap between the Hithaeglir and the Ered Mithrin.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1233, 'Mulkan', 'village', 100, '100% Lossoth', 'Mulkan is a Lossoth settlement in the frozen wastes of Forochel, established as a seasonal base for hunting and gathering. In summer, it consists of hide tents and driftwood shelters around a communal fire; in winter, the Lossoth build their remarkable snow-and-ice houses, low-roofed and surprisingly warm inside. Strangers are mistrusted, but those who arrive with trade goods — iron, cloth, salt — may be received with cautious hospitality.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1234, 'Nansret', 'village', 140, '100% Beffraen', 'Nansret is the only known village of the Beffraen, the Wild Men of the Rast Vorn. It is a rough settlement of bark shelters and timber lean-tos in the densest part of the forest, deliberately difficult to find. The Beffraen do not welcome outsiders; the village exists to support their hunting and gathering, and its location shifts with the seasons.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1235, 'Nardol', 'watchtower', 85, '100% Gondorian', 'Built by Tarostar of Gondor to replace a wooden signal-platform on the site; completed in T.A. 516.. A link in Gondor''s communications network along the Old North Road.. Nardol is the third beacon in the chain.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1236, 'Nogothiant', 'bridge', 0, 'N/A', 'Built by the Naugrim of Moria before S.A. 1693.. Passage across the Anduin on the Great East Road.. The Nogothiant is crumbling, having lasted without maintenance for many centuries.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1237, 'Nogrod', 'ruins', 0, 'N/A', 'First delved in the Early First Age.. The mining, smelting, and working of precious metals found in the Ered Luin.. Nogrod was destroyed in the cataclysm that sank Beleriand beneath the ocean.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1238, 'Ostigurth', 'fortified city', 2560, '40% Orc, 40% Haradan, 15% Easterling, 5% Troll', 'Built by Sauron in the mid-Second Age.. Control of traffic in the Den Nurn; the manufacture of finished products; small-scale trade.. Ostigurth is situated at the head of a small canyon on the southern edge of Gorgoroth.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1239, 'Paths Of The Dead', 'dungeon', 0, 'N/A', 'The Paths of the Dead are natural caverns beneath the White Mountains, connecting the vale of Dunharrow to the Morthond valley — once used as royal burial chambers by the Daen Coentis, last interred in T.A. 679. The entrance is known, but no living person willingly passes inside. Locals speak of cold air, a sense of invisible presences, and sounds that have no natural explanation. The broken Oath of the Dead men lingers here; the caverns are considered one of the most accursed places in Gondor.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1240, 'Pellardur', 'castle', 180, '50% Haradan, 30% Coastal People, 15% Corsair, 5% Black Númenórean', 'Built by the Captains of Umbar, circa T.A. 750.. Defense of southern land approaches to the city of Umbar; administration of surrounding farmlands.. Pellardur is situated close to the City of Umbar and rests in fairly fertile agricultural lands.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1241, 'Riavod', 'fortified town', 1060, '100% Easterling', 'Settled by Easterlings, circa T.A. 1408.. A trading base for expeditions up the Celduin; a port on the Sea of Rhûn.. Although ruled by a Sagath prince, the Dorwinrim use the town as their main trading base with the lands of Western Endor.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1242, 'Romenost', 'village', 95, '100% Gondorian', 'Romenost is a Gondorian waystation on the Men Romen, built by the Eastern Army to defend the road against incursions from the east. Its stone walls and barracks are practical rather than impressive; the garrison is small and the surrounding steppe is empty and windswept. Travellers on the Men Romen are glad to see it — it is the only shelter for many miles.');
INSERT INTO locations (id, name, location_type, inhabitants, description) VALUES (1243, 'Saarkaana', 'fortress', '?', 'Possibly Númenórean (?).. Unknown, possibly ceremonial.. Saarkaana is an Umbarean fortress in the parched Talath Naur, situated near the ruins of a Second Age structure.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1244, 'Sook Asni', 'town', 680, '90% Haradan, 10% Corsair', 'Settled by Haradrim, circa T.A. 1400.. Fishing; ship building and repair.. The lacquered tableware created by the craftsmen of Sook Asni is much in demand among the nobility of Umbar.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1245, 'Spathlin', 'town', 820, '90% Gondorian, 10% Dunnish', 'Settled by Gondor, circa T.A. 410.. Trading center at the confluence of the Rivers Ciril and Ringló; a collecting point for local farms.. Spathlin controls much of the river traffic to northern Lamedon, but it suffers nonetheless from isolation.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1246, 'Staddle', 'village', 90, '70% Stoor Hobbit, 30% Bree-man', 'Settled by Bree-land farmers, circa T.A. 1250.. Agriculture.. Staddle is just a short walk from Bree, and it relies upon its larger neighbor for most of the services a small agrarian community cannot provide for itself.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1247, 'Strayhold', 'fortified town', 900, '85% Northman, 15% Mixed Mannish', 'Settled by Gramuz outcasts, circa T.A. 1340.. Trade with Gramuz and Gondor; a local economic focal point.. Strayhold rests near the eastern edge of Mirkwood, situated in a deep gorge near the edge of the Talath Harroch.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1248, 'Sudúri', 'fortified city', 6000, '95% Dunnish, 5% Cardolani', 'Founded by the adventurer Gordaigh in T.A. 1503 on site of a Dúnadan fortress.. Administrative center for the Kingdom of Saralainn; a meeting place for Dunnish tribes.. The town was originally built by Númenóreans, but now almost all of the inhabitants are Dunnish in origin.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1249, 'Thalion', 'palace', 45, '60% Cardolani, 40% Eriadoran', 'Built by Tarcil of Arnor in T.A. 514.. The seat of House of Dol Tinare.. Thalion is in a sorry state of repair.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1250, 'Tharagrond', 'fortress', 65, '100% Black Númenórean', 'Founded by Númenórean colonists c. S.A. 2300.. Defense of the lands of the Principality of Tharagrond; local administration.. Tharagrond is a small and isolated fief, but it carries its autonomy proudly.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1251, 'Thorontir', 'fortress', 1350, '80% Gondorian, 20% Mixed Mannish', 'Founded by Gondor, circa T.A. 500.. A center for regional administration; a garrison for Gondor''s Eastern Army.. The fortress is located just off the Men Romen, several miles east of the town of Thorontir.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1252, 'Tir Anduin', 'castle', 2500, '90% Gondorian, 10% Northman', 'Settled by Gondorians, circa T.A. 1402; granted royal charter in T.A. 1560.. Northernmost significant Gondorian trading outpost; location of a ferry across the Anduin.. The ferry of Tir Anduin and the nearby ford at the Undeeps are the safest crossings of the Anduin between Osgiliath and the Old Ford.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1253, 'Tir Limlight', 'fortified town', 156, '60% Gondorian, 40% Northman', 'Tir Limlight marks the effective northern limit of Gondorian authority on the Anduin, guarding one of the few crossings at the Undeeps. Founded by Gondorian merchants, it has grown into a walled town of mixed Gondorian and Northman character — stone houses and timber warehouses, the smell of river trade, and the constant awareness of the northern wilderness beyond the walls. The garrison here watches for threats from Rhovanion as much as it watches the river traffic.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1254, 'Tir Nindor', 'castle', 60, '90% Gondorian, 10% Mixed Mannish', 'Constructed by Gondor around T.A. 410.. Guarding the only safe and dry passage through the Dead Marshes.. Tir Nindor is a strategic castle guarding the passage through the Dead Marshes.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1255, 'Towers Of The Teeth', 'watchtower', 340, '100% Gondorian', 'The Towers of the Teeth — Narchost and Carchost — flank the Cirith Gorgor on either side of the Morannon, built by Gondor in the first year of the Third Age to observe all traffic attempting to enter or leave Mordor. They are forbidding structures of black stone on bare crags; their garrison peers down at the ash-plain of Udûn below and reports any movement. No one passes into Mordor without being seen.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1256, 'Tuckburrow', 'village', 320, '90% Fallohide, 10% Stoor & Harfoot', 'Settled by Hobbits during the migration to the Shire, T.A. 1601-1610.. Clan dwelling; agriculture.. The village is located in the Green-hill country of the Westfarthing of the Shire.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1257, 'Umbar', 'fortified town', 60000, '35% Coastal People, 30% Corsair, 25% Haradan, 10% Black Númenórean', 'Founded by Tar-Atanamir of Númenor in S.A. 2280, expanded several times.. Capital of Umbar; economic and political center; ship building and repair.. A great monument raised by the Númenórean King Ar-Pharazôn to commemorate his victory over Sauron guards the entrance to the harbor.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1258, 'Vamag', 'ruins', 0, 'N/A', 'Vamag is a coastal ruin of the mid-Second Age, said to have served as a retreat for Adûnaphel — believed by some to be one of the Nazgûl. The local Coastal Peoples refuse to approach it, declaring the site haunted. The walls stand dark and salt-worn above the cliffs, and the silence around them feels heavier than it should.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1259, 'Warfinger', 'village', 54, '100% Gondorian', 'Built by the Gondorian Eastern Army around T.A. 1428.. A waystation along the south fork of the Men Romen; a defensive point against invasion from the East.. The small garrison at Warfinger is situated far away from the authority of the Regent in Thorontir.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1260, 'Woodmen-town', 'village', 200, '100% Woodman (Northman)', 'Settled permanently around T.A. 1580.. A gathering place for the Woodman clans; the home of the Althyn; the site of an annual fair.. Woodmen-town is built upon great platforms in the trees in the Elvish manner, for the Woodmen are on friendly terms with the Elves of the Forest.');
INSERT INTO locations (id, name, location_type, population, inhabitants, description) VALUES (1261, 'Wraecaburg', 'fortified town', 340, '80% Northman, 20% Mixed Mannish', 'Settled by Northmen around T.A. 1000.. Agriculture; a center for trade in the northern Anduin Vales.. Though not directly under the sway of the Witch-king, Wraecaburg suffers from frequent raids, despair, and a large population of shady characters from beyond Rhovanion.');